@media (max-width: 1200px) {
  .stats-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .split {
    grid-template-columns: 1fr;
  }

  .filter-input {
    min-width: 220px;
  }
}

@media (max-width: 700px) {
  .stats-grid {
    grid-template-columns: 1fr;
  }

  .panel-head {
    flex-direction: column;
    align-items: flex-start;
    gap: 10px;
  }

  .trend-row,
  .mini-row,
  .history-item {
    grid-template-columns: 1fr 1fr;
  }
}

import { of } from 'rxjs';
import {
  DeliveryAdminKpis,
  DeliveryRequest,
  DeliveryRequestService
} from '../../services/delivery-request.service';
import { DeliveryAdminOverviewComponent } from './delivery-admin-overview.component';

describe('DeliveryAdminOverviewComponent', () => {
  const now = Date.now();
  const recentDate = new Date(now - 2 * 24 * 60 * 60 * 1000).toISOString();
  const oldDate = new Date(now - 120 * 24 * 60 * 60 * 1000).toISOString();

  const requests: DeliveryRequest[] = [
    {
      id: '1',
      reference: 'DLV-001',
      product: 'Tomates',
      weightKg: 200,
      details: '',
      pickupLabel: 'Sousse',
      dropoffLabel: 'Tunis',
      estimatedPrice: 100,
      pickupLat: 35.82,
      pickupLng: 10.63,
      dropoffLat: 36.8,
      dropoffLng: 10.17,
      autoGrouping: false,
      status: 'Livrée',
      createdByRole: 'Agriculteur',
      createdByEmail: 'farmer1@test.tn',
      createdById: 10,
      acceptedByEmail: 'transporter1@test.tn',
      acceptedById: 30,
      createdAt: recentDate,
      deliveredAt: recentDate
    },
    {
      id: '2',
      reference: 'DLV-002',
      product: 'Pommes de terre',
      weightKg: 320,
      details: '',
      pickupLabel: 'Kairouan',
      dropoffLabel: 'Ariana',
      estimatedPrice: 180,
      pickupLat: 35.67,
      pickupLng: 10.1,
      dropoffLat: 36.86,
      dropoffLng: 10.19,
      autoGrouping: true,
      status: 'En cours',
      createdByRole: 'Agriculteur',
      createdByEmail: 'farmer2@test.tn',
      createdById: 11,
      acceptedByEmail: 'transporter2@test.tn',
      acceptedById: 31,
      createdAt: oldDate
    }
  ];

  const kpis: DeliveryAdminKpis = {
    total: 2,
    enAttente: 0,
    acceptees: 0,
    enCours: 1,
    livre: 1,
    annulees: 0,
    revenue: 100,
    avgPrice: 140,
    tauxLivraison: 50
  };

  function createComponent(customRequests: DeliveryRequest[] = requests, customKpis: DeliveryAdminKpis = kpis): DeliveryAdminOverviewComponent {
    const serviceMock = {
      refreshFromBackend: jasmine.createSpy('refreshFromBackend').and.returnValue(of(customRequests)),
      getAdminKpis: jasmine.createSpy('getAdminKpis').and.returnValue(of(customKpis))
    } as unknown as DeliveryRequestService;

    return new DeliveryAdminOverviewComponent(serviceMock);
  }

  it('loads complete admin statistics and ranking data', () => {
    const component = createComponent();

    component.ngOnInit();

    expect(component.stats.total).toBe(2);
    expect(component.stats.deliveryRate).toBe(50);
    expect(component.statusBreakdown.length).toBe(5);
    expect(component.monthlyTrend.length).toBe(6);
    expect(component.topTransporters.length).toBe(2);
    expect(component.topProducts.length).toBe(2);
  });

  it('filters displayed rows by status, period and search term', () => {
    const component = createComponent();

    component.ngOnInit();
    component.statusFilter = 'Livrée';
    expect(component.displayedRows.length).toBe(1);

    component.statusFilter = 'ALL';
    component.periodFilter = '30D';
    expect(component.displayedRows.length).toBe(1);

    component.periodFilter = 'ALL';
    component.searchTerm = 'pommes';
    expect(component.displayedRows.length).toBe(1);
    expect(component.displayedRows[0].reference).toBe('DLV-002');
  });
});

import { Component, OnInit } from '@angular/core';
import { DeliveryRequest, DeliveryRequestService } from '../../services/delivery-request.service';

type AdminDeliveryRow = {
  id: string;
  reference: string;
  status: string;
  product: string;
  weightKg: number;
  price: number;
  farmer: string;
  transporter: string;
  createdAt: string;
  deliveredAt: string;
};

type AdminStats = {
  total: number;
  pending: number;
  accepted: number;
  inProgress: number;
  delivered: number;
  refused: number;
  totalAmount: number;
  activeTransporters: number;
};

@Component({
  selector: 'app-delivery-admin-overview',
  templateUrl: './delivery-admin-overview.component.html',
  styleUrls: ['./delivery-admin-overview.component.css']
})
export class DeliveryAdminOverviewComponent implements OnInit {
  isLoading = false;
  loadError: string | null = null;

  rows: AdminDeliveryRow[] = [];
  stats: AdminStats = {
    total: 0,
    pending: 0,
    accepted: 0,
    inProgress: 0,
    delivered: 0,
    refused: 0,
    totalAmount: 0,
    activeTransporters: 0
  };

  constructor(private requestService: DeliveryRequestService) {}

  ngOnInit(): void {
    this.reload();
  }

  reload(): void {
    this.isLoading = true;
    this.loadError = null;

    this.requestService.refreshFromBackend().subscribe({
      next: (requests) => {
        this.rows = this.toRows(requests);
        this.stats = this.computeStats(requests);
        this.isLoading = false;
      },
      error: () => {
        this.rows = [];
        this.stats = {
          total: 0,
          pending: 0,
          accepted: 0,
          inProgress: 0,
          delivered: 0,
          refused: 0,
          totalAmount: 0,
          activeTransporters: 0
        };
        this.loadError = 'Unable to load administrator data.';
        this.isLoading = false;
      }
    });
  }

  get historyRows(): AdminDeliveryRow[] {
    return this.rows.slice(0, 12);
  }

  private toRows(requests: DeliveryRequest[]): AdminDeliveryRow[] {
    return requests
      .map((request) => ({
        id: request.id,
        reference: request.reference,
        status: request.status,
        product: request.product,
        weightKg: request.weightKg,
        price: Number(request.estimatedPrice || 0),
        farmer: request.createdByEmail || 'Farmer',
        transporter: request.acceptedByEmail || 'Not assigned',
        createdAt: this.toDateTime(request.createdAt),
        deliveredAt: request.deliveredAt ? this.toDateTime(request.deliveredAt) : '—'
      }))
      .sort((a, b) => (a.createdAt < b.createdAt ? 1 : -1));
  }

  private computeStats(requests: DeliveryRequest[]): AdminStats {
    const activeTransporters = new Set(
      requests
        .filter((request) => Boolean(request.acceptedByEmail))
        .map((request) => request.acceptedByEmail as string)
    ).size;

    return {
      total: requests.length,
      pending: requests.filter((request) => request.status === 'En attente').length,
      accepted: requests.filter((request) => request.status === 'Acceptée').length,
      inProgress: requests.filter((request) => request.status === 'En cours').length,
      delivered: requests.filter((request) => request.status === 'Livrée').length,
      refused: requests.filter((request) => request.status === 'Refusée').length,
      totalAmount: requests.reduce((sum, request) => sum + Number(request.estimatedPrice || 0), 0),
      activeTransporters
    };
  }

  private toDateTime(value: string): string {
    const date = new Date(value);
    if (Number.isNaN(date.getTime())) {
      return value;
    }

    return date.toLocaleString('fr-FR', {
      day: '2-digit',
      month: 'short',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  }
}

import { Component, OnInit } from '@angular/core';
import { forkJoin } from 'rxjs';
import {
  DeliveryAdminKpis,
  DeliveryRequest,
  DeliveryRequestService
} from '../../services/delivery-request.service';

type AdminDeliveryRow = {
  id: string;
  reference: string;
  status: string;
  product: string;
  weightKg: number;
  price: number;
  farmer: string;
  transporter: string;
  createdAtRaw: string;
  createdAtTs: number;
  createdAt: string;
  deliveredAtRaw: string;
  deliveredAt: string;
};

type AdminStatusFilter = 'ALL' | 'En attente' | 'Acceptée' | 'En cours' | 'Livrée' | 'Refusée';
type AdminPeriodFilter = 'ALL' | '7D' | '30D' | '90D';

type StatusBreakdownItem = {
  label: string;
  count: number;
  percent: number;
  className: string;
};

type MonthlyTrendItem = {
  label: string;
  created: number;
  delivered: number;
  revenue: number;
};

type TopTransporter = {
  name: string;
  handled: number;
  delivered: number;
  revenue: number;
};

type TopProduct = {
  name: string;
  deliveries: number;
  totalWeight: number;
  totalAmount: number;
};

type AdminStats = {
  total: number;
  pending: number;
  accepted: number;
  inProgress: number;
  delivered: number;
  refused: number;
  totalAmount: number;
  revenue: number;
  avgPrice: number;
  deliveryRate: number;
  cancellationRate: number;
  inProgressRate: number;
  activeTransporters: number;
};

@Component({
  selector: 'app-delivery-admin-overview',
  templateUrl: './delivery-admin-overview.component.html',
  styleUrls: ['./delivery-admin-overview.component.css']
})
export class DeliveryAdminOverviewComponent implements OnInit {
  isLoading = false;
  loadError: string | null = null;
  searchTerm = '';
  statusFilter: AdminStatusFilter = 'ALL';
  periodFilter: AdminPeriodFilter = 'ALL';

  rows: AdminDeliveryRow[] = [];
  statusBreakdown: StatusBreakdownItem[] = [];
  monthlyTrend: MonthlyTrendItem[] = [];
  topTransporters: TopTransporter[] = [];
  topProducts: TopProduct[] = [];
  stats: AdminStats = {
    total: 0,
    pending: 0,
    accepted: 0,
    inProgress: 0,
    delivered: 0,
    refused: 0,
    totalAmount: 0,
    revenue: 0,
    avgPrice: 0,
    deliveryRate: 0,
    cancellationRate: 0,
    inProgressRate: 0,
    activeTransporters: 0
  };

  constructor(private requestService: DeliveryRequestService) {}

  ngOnInit(): void {
    this.reload();
  }

  reload(): void {
    this.isLoading = true;
    this.loadError = null;

    forkJoin({
      requests: this.requestService.refreshFromBackend(),
      kpis: this.requestService.getAdminKpis()
    }).subscribe({
      next: ({ requests, kpis }) => {
        this.rows = this.toRows(requests);
        this.stats = this.computeStats(requests, kpis);
        this.statusBreakdown = this.buildStatusBreakdown(this.stats);
        this.monthlyTrend = this.buildMonthlyTrend(this.rows);
        this.topTransporters = this.buildTopTransporters(this.rows);
        this.topProducts = this.buildTopProducts(this.rows);
        this.isLoading = false;
      },
      error: () => {
        this.rows = [];
        this.statusBreakdown = [];
        this.monthlyTrend = [];
        this.topTransporters = [];
        this.topProducts = [];
        this.stats = {
          total: 0,
          pending: 0,
          accepted: 0,
          inProgress: 0,
          delivered: 0,
          refused: 0,
          totalAmount: 0,
          revenue: 0,
          avgPrice: 0,
          deliveryRate: 0,
          cancellationRate: 0,
          inProgressRate: 0,
          activeTransporters: 0
        };
        this.loadError = 'Unable to load administrator data.';
        this.isLoading = false;
      }
    });
  }

  get displayedRows(): AdminDeliveryRow[] {
    const periodMs: Record<Exclude<AdminPeriodFilter, 'ALL'>, number> = {
      '7D': 7 * 24 * 60 * 60 * 1000,
      '30D': 30 * 24 * 60 * 60 * 1000,
      '90D': 90 * 24 * 60 * 60 * 1000
    };

    const normalizedQuery = this.searchTerm.trim().toLowerCase();
    const now = Date.now();

    return this.rows.filter((row) => {
      if (this.statusFilter !== 'ALL' && row.status !== this.statusFilter) {
        return false;
      }

      if (this.periodFilter !== 'ALL') {
        const threshold = now - periodMs[this.periodFilter];
        if (row.createdAtTs <= 0 || row.createdAtTs < threshold) {
          return false;
        }
      }

      if (!normalizedQuery) {
        return true;
      }

      const haystack = `${row.reference} ${row.product} ${row.farmer} ${row.transporter}`.toLowerCase();
      return haystack.includes(normalizedQuery);
    });
  }

  get historyRows(): AdminDeliveryRow[] {
    return this.displayedRows.slice(0, 12);
  }

  private toRows(requests: DeliveryRequest[]): AdminDeliveryRow[] {
    return requests
      .map((request) => ({
        id: request.id,
        reference: request.reference,
        status: request.status,
        product: request.product,
        weightKg: request.weightKg,
        price: Number(request.estimatedPrice || 0),
        farmer: request.createdByEmail || 'Farmer',
        transporter: request.acceptedByEmail || 'Not assigned',
        createdAtRaw: request.createdAt,
        createdAtTs: this.toTimestamp(request.createdAt),
        createdAt: this.toDateTime(request.createdAt),
        deliveredAtRaw: request.deliveredAt || '',
        deliveredAt: request.deliveredAt ? this.toDateTime(request.deliveredAt) : '—'
      }))
      .sort((a, b) => b.createdAtTs - a.createdAtTs);
  }

  private computeStats(requests: DeliveryRequest[], kpis: DeliveryAdminKpis): AdminStats {
    const total = kpis.total > 0 ? kpis.total : requests.length;
    const pending = kpis.enAttente > 0 ? kpis.enAttente : requests.filter((request) => request.status === 'En attente').length;
    const accepted = kpis.acceptees > 0 ? kpis.acceptees : requests.filter((request) => request.status === 'Acceptée').length;
    const inProgress = kpis.enCours > 0 ? kpis.enCours : requests.filter((request) => request.status === 'En cours').length;
    const delivered = kpis.livre > 0 ? kpis.livre : requests.filter((request) => request.status === 'Livrée').length;
    const refused = kpis.annulees > 0 ? kpis.annulees : requests.filter((request) => request.status === 'Refusée').length;
    const totalAmount = requests.reduce((sum, request) => sum + Number(request.estimatedPrice || 0), 0);
    const revenue = kpis.revenue > 0
      ? kpis.revenue
      : requests
          .filter((request) => request.status === 'Livrée')
          .reduce((sum, request) => sum + Number(request.estimatedPrice || 0), 0);

    const activeTransporters = new Set(
      requests
        .filter((request) => Boolean(request.acceptedByEmail))
        .map((request) => request.acceptedByEmail as string)
    ).size;

    const deliveryRate = kpis.tauxLivraison > 0
      ? kpis.tauxLivraison
      : (total > 0 ? (delivered * 100) / total : 0);

    return {
      total,
      pending,
      accepted,
      inProgress,
      delivered,
      refused,
      totalAmount: this.round2(totalAmount),
      revenue: this.round2(revenue),
      avgPrice: this.round2(kpis.avgPrice > 0 ? kpis.avgPrice : (total > 0 ? totalAmount / total : 0)),
      deliveryRate: this.round2(deliveryRate),
      cancellationRate: this.round2(total > 0 ? (refused * 100) / total : 0),
      inProgressRate: this.round2(total > 0 ? (inProgress * 100) / total : 0),
      activeTransporters
    };
  }

  private buildStatusBreakdown(stats: AdminStats): StatusBreakdownItem[] {
    return [
      { label: 'Pending', count: stats.pending, percent: stats.total > 0 ? (stats.pending * 100) / stats.total : 0, className: 'pending' },
      { label: 'Accepted', count: stats.accepted, percent: stats.total > 0 ? (stats.accepted * 100) / stats.total : 0, className: 'accepted' },
      { label: 'In progress', count: stats.inProgress, percent: stats.total > 0 ? (stats.inProgress * 100) / stats.total : 0, className: 'progress' },
      { label: 'Delivered', count: stats.delivered, percent: stats.total > 0 ? (stats.delivered * 100) / stats.total : 0, className: 'delivered' },
      { label: 'Refused', count: stats.refused, percent: stats.total > 0 ? (stats.refused * 100) / stats.total : 0, className: 'refused' }
    ].map((item) => ({ ...item, percent: this.round2(item.percent) }));
  }

  private buildMonthlyTrend(rows: AdminDeliveryRow[]): MonthlyTrendItem[] {
    const months = 6;
    const now = new Date();
    const trend: MonthlyTrendItem[] = [];

    for (let i = months - 1; i >= 0; i -= 1) {
      const bucketDate = new Date(now.getFullYear(), now.getMonth() - i, 1);
      const month = bucketDate.getMonth();
      const year = bucketDate.getFullYear();

      const monthRows = rows.filter((row) => {
        const date = new Date(row.createdAtRaw);
        return date.getMonth() === month && date.getFullYear() === year;
      });

      trend.push({
        label: bucketDate.toLocaleDateString('en-US', { month: 'short' }),
        created: monthRows.length,
        delivered: monthRows.filter((row) => row.status === 'Livrée').length,
        revenue: this.round2(
          monthRows
            .filter((row) => row.status === 'Livrée')
            .reduce((sum, row) => sum + row.price, 0)
        )
      });
    }

    return trend;
  }

  private buildTopTransporters(rows: AdminDeliveryRow[]): TopTransporter[] {
    const grouped = new Map<string, TopTransporter>();

    rows.forEach((row) => {
      if (!row.transporter || row.transporter === 'Not assigned') {
        return;
      }

      const current = grouped.get(row.transporter) || {
        name: row.transporter,
        handled: 0,
        delivered: 0,
        revenue: 0
      };

      current.handled += 1;
      if (row.status === 'Livrée') {
        current.delivered += 1;
        current.revenue += row.price;
      }
      grouped.set(row.transporter, current);
    });

    return Array.from(grouped.values())
      .map((entry) => ({ ...entry, revenue: this.round2(entry.revenue) }))
      .sort((a, b) => {
        if (b.delivered !== a.delivered) {
          return b.delivered - a.delivered;
        }
        return b.handled - a.handled;
      })
      .slice(0, 5);
  }

  private buildTopProducts(rows: AdminDeliveryRow[]): TopProduct[] {
    const grouped = new Map<string, TopProduct>();

    rows.forEach((row) => {
      const name = row.product || 'Produit';
      const current = grouped.get(name) || {
        name,
        deliveries: 0,
        totalWeight: 0,
        totalAmount: 0
      };

      current.deliveries += 1;
      current.totalWeight += row.weightKg;
      current.totalAmount += row.price;
      grouped.set(name, current);
    });

    return Array.from(grouped.values())
      .map((entry) => ({
        ...entry,
        totalWeight: this.round2(entry.totalWeight),
        totalAmount: this.round2(entry.totalAmount)
      }))
      .sort((a, b) => b.deliveries - a.deliveries)
      .slice(0, 5);
  }

  private toTimestamp(value: string): number {
    const date = new Date(value);
    return Number.isNaN(date.getTime()) ? 0 : date.getTime();
  }

  private round2(value: number): number {
    return Math.round((value + Number.EPSILON) * 100) / 100;
  }

  private toDateTime(value: string): string {
    const date = new Date(value);
    if (Number.isNaN(date.getTime())) {
      return value;
    }

    return date.toLocaleString('fr-FR', {
      day: '2-digit',
      month: 'short',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  }
}

import { Component, OnInit, OnDestroy, AfterViewInit, ViewChild, ElementRef } from '@angular/core';
import { DeliveryMapService } from '../../services/delivery-map.service';
import { DeliveryRequestService } from '../../services/delivery-request.service';
import { ActivatedRoute, Router } from '@angular/router';
import { getDeliveryUserRole } from '../../services/delivery-auth.helper';

type DeliveryStatus = 'En attente' | 'Acceptée' | 'En cours' | 'Livrée' | 'Refusée';

type TrackingNotification = {
  type: 'success' | 'error' | 'info';
  title: string;
  message: string;
};

type TrackingItem = {
  id: string;
  reference: string;
  product: string;
  status: DeliveryStatus;
  realStatus: DeliveryStatus;
  pickup: string;
  dropoff: string;
  pickupLat?: number;
  pickupLng?: number;
  dropoffLat?: number;
  dropoffLng?: number;
  currentLat?: number;
  currentLng?: number;
  progress: number;
  etaMinutes: number;
  ownerId?: number;
  farmerId?: number;
  transporterId?: number;
  farmerName?: string;
  transporterName?: string;
  rating?: number;
  ratingStatus?: 'PENDING' | 'RATED' | 'IGNORED';
  hasLivePosition?: boolean;
};

type TransporterProfile = {
  displayName: string;
  totalDeliveries: number;
  successRate: number;
  avgRating: number;
};

@Component({
  selector: 'app-delivery-tracking',
  standalone: false,
  templateUrl: './delivery-tracking.component.html',
  styleUrls: ['./delivery-tracking.component.css']
})
export class DeliveryTrackingComponent implements OnInit, OnDestroy, AfterViewInit {
  @ViewChild('mapContainer', { static: false }) mapContainer?: ElementRef;

  role = getDeliveryUserRole();
  private currentUserId = this.requestService.getCurrentUserId();
  showAllStatusOption = true;

  statuses: DeliveryStatus[] = ['En attente', 'En cours', 'Livrée', 'Refusée'];
  selectedStatus: DeliveryStatus | 'Tous' = 'Tous';
  searchText = '';

  deliveries: TrackingItem[] = [];

  selectedId = '';
  notificationDeliveryId = '';
  notification: TrackingNotification | null = null;
  showDeleteDialog = false;
  pendingDeleteDelivery: TrackingItem | null = null;
  deleteInProgress = false;
  selectedRating = 5;
  ratingInProgress = false;
  selectedTransporterProfile: TransporterProfile | null = null;
  simulationRunning = false;
  simulationProgress = 0;

  private simulationTimerId: number | null = null;

  constructor(
    private mapService: DeliveryMapService,
    private requestService: DeliveryRequestService,
    private router: Router,
    private route: ActivatedRoute
  ) {}

  ngOnInit(): void {
    const isTransporter = this.role === 'transporteur' || this.role === 'transporter' || this.role.includes('transport');
    if (isTransporter) {
      this.router.navigate(['/delivery/active']);
      return;
    }

    this.loadDeliveries();
    this.route.queryParamMap.subscribe((params) => {
      this.notificationDeliveryId = params.get('deliveryId') || '';
      if (this.notificationDeliveryId) {
        this.selectedId = this.notificationDeliveryId;
        this.selectedStatus = 'Tous';
      }
      this.renderDeliveryRoute();
    });

    this.requestService.refreshFromBackend().subscribe(() => {
      this.loadDeliveries();
      this.selectedId = this.filteredDeliveries.find((delivery) => delivery.id === this.notificationDeliveryId)?.id
        || this.filteredDeliveries[0]?.id
        || '';
      this.renderDeliveryRoute();
    });
    this.showAllStatusOption = true;
    if (this.isFarmer()) {
      this.selectedStatus = 'Tous';
    }

    this.selectedId = this.filteredDeliveries.find((delivery) => delivery.id === this.notificationDeliveryId)?.id
      || this.filteredDeliveries[0]?.id
      || '';
  }

  ngAfterViewInit(): void {
    // Ensure map container is mounted before any marker rendering.
    this.initializeMap();
  }

  ngOnDestroy(): void {
    this.stopSimulation();
    this.mapService.destroy();
  }


  private initializeMap(): void {
    if (!this.mapContainer) return;

    const delivery = this.selectedDelivery;
    const hasPickup = Boolean(delivery?.pickupLat && delivery?.pickupLng);
    const centerLat = hasPickup
      ? ((delivery!.pickupLat as number) + ((delivery!.dropoffLat as number) || (delivery!.pickupLat as number))) / 2
      : 36.8065;
    const centerLng = hasPickup
      ? ((delivery!.pickupLng as number) + ((delivery!.dropoffLng as number) || (delivery!.pickupLng as number))) / 2
      : 10.1815;

    this.mapService.initMap(this.mapContainer.nativeElement, centerLat, centerLng, 10);
    this.renderDeliveryRoute();
  }

  private renderDeliveryRoute(): void {
    const delivery = this.selectedDelivery;
    if (!delivery) return;

    if (!this.mapService.getMap()) {
      this.initializeMap();
      if (!this.mapService.getMap()) {
        return;
      }
    }

    this.mapService.clear();

    if (delivery.pickupLat && delivery.pickupLng) {
      this.mapService.addMarker(
        delivery.pickupLat,
        delivery.pickupLng,
        `<strong>Departure:</strong> ${delivery.pickup}`,
        {
          title: 'Departure',
          zIndexOffset: 1000,
          icon: this.mapService.getPointIcon('start')
        }
      );
    }

    if (delivery.dropoffLat && delivery.dropoffLng) {
      this.mapService.addMarker(
        delivery.dropoffLat,
        delivery.dropoffLng,
        `<strong>Destination:</strong> ${delivery.dropoff}`,
        {
          title: 'Destination',
          zIndexOffset: 1000,
          icon: this.mapService.getPointIcon('end')
        }
      );
    }

    if (delivery.currentLat && delivery.currentLng && delivery.status === 'En cours') {
      this.mapService.addCircleMarker(delivery.currentLat, delivery.currentLng, 10, '#FF9800');
    }

    const routePoints = this.resolveRoutePoints(delivery);

    if (routePoints.length >= 2) {
      // Use OSRM for real road routing
      this.mapService.drawRouteOSRM(routePoints, '#4caf50', 5).then(() => {
        this.mapService.fitBounds(routePoints, 80);
      });
      this.mapService.getRouteGuidance(routePoints).then((guidance) => {
        if (!guidance) {
          return;
        }
        const selected = this.deliveries.find((item) => item.id === delivery.id);
        if (selected) {
          selected.etaMinutes = guidance.etaMinutes;
        }
      });
    }
  }

  get selectedDelivery(): TrackingItem | undefined {
    const source = this.filteredDeliveries;
    const selected = source.find((d) => d.id === this.selectedId);
    return selected || source[0];
  }

  get filteredDeliveries(): TrackingItem[] {
    const q = this.searchText.trim().toLowerCase();
    return this.deliveries.filter((d) => {
      const ownerOk = !this.isFarmer() || d.ownerId === this.currentUserId;
      const matchStatus = this.selectedStatus === 'Tous' || d.status === this.selectedStatus;
      const matchSearch = !q || (d.reference + ' ' + d.product + ' ' + d.pickup + ' ' + d.dropoff).toLowerCase().includes(q);
      return ownerOk && matchStatus && matchSearch;
    });
  }

  selectDelivery(id: string): void {
    this.selectedId = id;

    const delivery = this.selectedDelivery;
    if (!delivery || !delivery.pickupLat || !delivery.pickupLng) return;

    const map = this.mapService.getMap();
    if (!map) {
      this.initializeMap();
      return;
    }

    this.renderDeliveryRoute();
  }

  openDeliveryDetail(id: string, event?: Event): void {
    event?.stopPropagation();
    this.router.navigate(['/delivery/livraisons', id]);
  }

  editSelectedDelivery(): void {
    const delivery = this.selectedDelivery;
    if (!delivery) return;

    if (!this.canManageDelivery(delivery)) {
      this.pushNotification(
        'error',
        'Edit unavailable',
        'A request already accepted by a transporter can no longer be edited.'
      );
      return;
    }

    this.router.navigate(['/delivery/livraisons', delivery.id, 'edit']);
  }

  deleteSelectedDelivery(): void {
    const delivery = this.selectedDelivery;
    if (!delivery) return;

    if (!this.canManageDelivery(delivery)) {
      this.pushNotification(
        'error',
        'Deletion unavailable',
        'A request already accepted by a transporter can no longer be deleted.'
      );
      return;
    }

    this.pendingDeleteDelivery = delivery;
    this.showDeleteDialog = true;
  }

  canShowRatingPanel(delivery?: TrackingItem): boolean {
    if (!delivery || !this.isFarmer() || delivery.ownerId !== this.currentUserId) {
      return false;
    }
    if (delivery.status !== 'Livrée') {
      return false;
    }
    if ((delivery.rating || 0) > 0) {
      return false;
    }
    return delivery.ratingStatus !== 'IGNORED';
  }

  canShowRatedInfo(delivery?: TrackingItem): boolean {
    return Boolean(delivery && (delivery.rating || 0) > 0 && delivery.ownerId === this.currentUserId);
  }

  getFarmerDisplayName(delivery?: TrackingItem): string {
    if (delivery?.farmerName) {
      return delivery.farmerName;
    }
    return 'Farmer';
  }

  getTransporterDisplayName(delivery?: TrackingItem): string {
    if (delivery?.transporterName) {
      return delivery.transporterName;
    }
    return 'Transporter not assigned';
  }

  canOpenTransporterProfile(delivery?: TrackingItem): boolean {
    return Boolean(delivery?.transporterId && delivery.transporterId > 0);
  }

  openTransporterProfile(delivery?: TrackingItem): void {
    const transporterId = delivery?.transporterId || 0;
    if (!transporterId) {
      return;
    }

    const related = this.requestService.getAll().filter((item) => item.acceptedById === transporterId);
    const delivered = related.filter((item) => item.status === 'Livrée');
    const rated = delivered.filter((item) => Number(item.rating || 0) > 0);
    const successRate = related.length > 0 ? this.round2((delivered.length * 100) / related.length) : 0;
    const avgRating = rated.length > 0
      ? rated.reduce((sum, item) => sum + Number(item.rating || 0), 0) / rated.length
      : 0;

    this.selectedTransporterProfile = {
      displayName: this.getTransporterDisplayName(delivery),
      totalDeliveries: related.length,
      successRate,
      avgRating: this.round2(avgRating)
    };
  }

  closeTransporterProfile(): void {
    this.selectedTransporterProfile = null;
  }

  selectRating(value: number): void {
    if (value < 1 || value > 5 || this.ratingInProgress) {
      return;
    }
    this.selectedRating = value;
  }

  launchTrackingSimulation(): void {
    const delivery = this.selectedDelivery;
    if (!delivery || this.simulationRunning) {
      return;
    }

    this.stopSimulation();
    this.simulationRunning = true;
    this.simulationProgress = 0;

    const startLat = delivery.currentLat ?? delivery.pickupLat ?? 0;
    const startLng = delivery.currentLng ?? delivery.pickupLng ?? 0;
    const endLat = delivery.dropoffLat ?? startLat;
    const endLng = delivery.dropoffLng ?? startLng;

    this.simulationTimerId = window.setInterval(() => {
      if (!this.simulationRunning) {
        return;
      }

      this.simulationProgress = Math.min(100, this.simulationProgress + 20);
      const ratio = this.simulationProgress / 100;
      const lat = startLat + (endLat - startLat) * ratio;
      const lng = startLng + (endLng - startLng) * ratio;

      this.requestService.updateCurrentPosition(delivery.id, lat, lng).subscribe();

      if (this.simulationProgress >= 100) {
        this.stopSimulation();
      }
    }, 1000);
  }

  stopSimulation(): void {
    this.simulationRunning = false;
    if (this.simulationTimerId !== null) {
      window.clearInterval(this.simulationTimerId);
      this.simulationTimerId = null;
    }
  }

  submitRating(): void {
    const delivery = this.selectedDelivery;
    if (!delivery || !this.canShowRatingPanel(delivery) || this.ratingInProgress) {
      return;
    }

    this.ratingInProgress = true;
    this.requestService.evaluerTransporteur(delivery.id, this.selectedRating, this.currentUserId).subscribe((updated) => {
      this.ratingInProgress = false;
      if (!updated) {
        this.pushNotification('error', 'Rating not possible', 'The rating could not be saved.');
        return;
      }

      this.pushNotification('success', 'Thank you for your rating', `You rated this transporter ${this.selectedRating}/5.`);
      this.reloadDeliveries();
    });
  }

  ignoreRatingPrompt(): void {
    const delivery = this.selectedDelivery;
    if (!delivery || !this.canShowRatingPanel(delivery) || this.ratingInProgress) {
      return;
    }

    this.ratingInProgress = true;
    this.requestService.ignorerNotationTransporteur(delivery.id, this.currentUserId).subscribe((updated) => {
      this.ratingInProgress = false;
      if (!updated) {
        this.pushNotification('error', 'Action not possible', 'Unable to ignore this prompt at the moment.');
        return;
      }

      this.pushNotification('info', 'Rating skipped', 'You can continue without rating this transporter.');
      this.reloadDeliveries();
    });
  }

  closeDeleteDialog(): void {
    if (this.deleteInProgress) {
      return;
    }

    this.showDeleteDialog = false;
    this.pendingDeleteDelivery = null;
  }

  confirmDelete(): void {
    const delivery = this.pendingDeleteDelivery;
    if (!delivery || this.deleteInProgress) {
      return;
    }

    this.deleteInProgress = true;

    this.requestService.deleteApiDelivery(delivery.id).subscribe((deleted) => {
      this.deleteInProgress = false;
      this.showDeleteDialog = false;
      this.pendingDeleteDelivery = null;

      if (!deleted) {
        this.pushNotification(
          'error',
          'Deletion not possible',
          'The request may have already been accepted by a transporter. The list has been reloaded.'
        );
        this.reloadDeliveries();
        return;
      }

      this.pushNotification(
        'success',
        'Demande supprimée',
        `La demande ${delivery.reference} a été supprimée avec succès.`
      );
      this.reloadDeliveries();
    });
  }

  canManageSelectedDelivery(): boolean {
    return this.canManageDelivery(this.selectedDelivery);
  }

  trackIsActive(item: TrackingItem): boolean {
    return item.id === this.selectedId;
  }

  isFarmer(): boolean {
    return this.role === 'agriculteur' || this.role === 'farmer' || this.role.includes('agric');
  }

  private canManageDelivery(delivery?: TrackingItem): boolean {
    return Boolean(
      delivery &&
      this.isFarmer() &&
      delivery.ownerId === this.currentUserId &&
      delivery.realStatus === 'En attente'
    );
  }

  private loadDeliveries(): void {
    const requests = this.requestService.getAll();
    this.deliveries = requests.map((r) => {
      const inProgress = r.status === 'En cours';
      const delivered = r.status === 'Livrée';
      const accepted = r.status === 'Acceptée';
      const displayStatus: DeliveryStatus = accepted ? 'En attente' : (r.status as DeliveryStatus);
      const hasRealGps = Boolean(r.currentLat && r.currentLng);
      return {
        id: r.id,
        reference: r.reference,
        product: r.product,
        status: displayStatus,
        realStatus: r.status as DeliveryStatus,
        pickup: r.pickupLabel,
        dropoff: r.dropoffLabel,
        pickupLat: r.pickupLat,
        pickupLng: r.pickupLng,
        dropoffLat: r.dropoffLat,
        dropoffLng: r.dropoffLng,
        currentLat: r.currentLat || (delivered ? r.dropoffLat : undefined),
        currentLng: r.currentLng || (delivered ? r.dropoffLng : undefined),
        progress: delivered ? 100 : (inProgress && hasRealGps)
          ? this.computeProgress(r.pickupLat, r.pickupLng, r.dropoffLat, r.dropoffLng, r.currentLat!, r.currentLng!)
          : 0,
        etaMinutes: 0,
        ownerId: r.createdById,
        farmerId: r.createdById,
        transporterId: r.acceptedById,
        farmerName: this.formatPersonName(r.createdByEmail, 'Agriculteur', r.createdById),
        transporterName: this.formatPersonName(r.acceptedByEmail, 'Transporteur', r.acceptedById),
        rating: r.rating,
        ratingStatus: r.ratingStatus,
        hasLivePosition: hasRealGps
      };
    });
  }

  private resolveRoutePoints(delivery: TrackingItem): { lat: number; lng: number }[] {
    const points: { lat: number; lng: number }[] = [];

    if (delivery.status === 'En cours' && delivery.currentLat && delivery.currentLng) {
      points.push({ lat: delivery.currentLat, lng: delivery.currentLng });
      if (delivery.dropoffLat && delivery.dropoffLng) {
        points.push({ lat: delivery.dropoffLat, lng: delivery.dropoffLng });
      }
      return points;
    }

    if (delivery.pickupLat && delivery.pickupLng) {
      points.push({ lat: delivery.pickupLat, lng: delivery.pickupLng });
    }
    if (delivery.dropoffLat && delivery.dropoffLng) {
      points.push({ lat: delivery.dropoffLat, lng: delivery.dropoffLng });
    }
    return points;
  }

  private computeProgress(
    pickupLat: number, pickupLng: number,
    dropoffLat: number, dropoffLng: number,
    currentLat: number, currentLng: number
  ): number {
    const total = this.haversine(pickupLat, pickupLng, dropoffLat, dropoffLng);
    if (total === 0) return 0;
    const done = this.haversine(pickupLat, pickupLng, currentLat, currentLng);
    return Math.min(100, Math.round((done / total) * 100));
  }

  private haversine(lat1: number, lng1: number, lat2: number, lng2: number): number {
    const R = 6371;
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLng = (lng2 - lng1) * Math.PI / 180;
    const a = Math.sin(dLat / 2) ** 2
      + Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) * Math.sin(dLng / 2) ** 2;
    return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  }

  private reloadDeliveries(): void {
    this.requestService.refreshFromBackend().subscribe(() => {
      this.loadDeliveries();
      this.selectedId = this.filteredDeliveries.find((delivery) => delivery.id === this.selectedId)?.id
        || this.filteredDeliveries[0]?.id
        || '';
      this.renderDeliveryRoute();
    });
  }

  private pushNotification(type: TrackingNotification['type'], title: string, message: string): void {
    this.notification = { type, title, message };
    window.setTimeout(() => (this.notification = null), 3500);
  }

  private round2(value: number): number {
    return Math.round(value * 100) / 100;
  }

  private formatPersonName(email?: string, fallbackRole: 'Agriculteur' | 'Transporteur' = 'Agriculteur', id?: number): string {
    if (email && email.includes('@')) {
      const localPart = email.split('@')[0];
      const normalized = localPart
        .replace(/[-_.]+/g, ' ')
        .replace(/\b(transporter|transporteur|farmer|agriculteur)\b/gi, '')
        .replace(/\s+/g, ' ')
        .replace(/\b\w/g, (letter) => letter.toUpperCase())
        .trim();
      if (normalized) {
        return normalized;
      }
    }
    return fallbackRole;
  }
}

import { Component, OnInit, OnDestroy, AfterViewInit, ViewChild, ElementRef } from '@angular/core';
import { DeliveryMapService } from '../../services/delivery-map.service';
import { DeliveryRequestService } from '../../services/delivery-request.service';
import { ActivatedRoute, Router } from '@angular/router';

type DeliveryStatus = 'En attente' | 'Acceptée' | 'En cours' | 'Livrée' | 'Refusée';

type TrackingNotification = {
  type: 'success' | 'error' | 'info';
  title: string;
  message: string;
};

type TrackingItem = {
  id: string;
  reference: string;
  product: string;
  status: DeliveryStatus;
  realStatus: DeliveryStatus;
  pickup: string;
  dropoff: string;
  pickupLat?: number;
  pickupLng?: number;
  dropoffLat?: number;
  dropoffLng?: number;
  currentLat?: number;
  currentLng?: number;
  progress: number;
  etaMinutes: number;
  ownerId?: number;
  farmerId?: number;
  transporterId?: number;
  farmerName?: string;
  transporterName?: string;
  rating?: number;
  ratingStatus?: 'PENDING' | 'RATED' | 'IGNORED';
  hasLivePosition?: boolean;
};

type TransporterProfile = {
  displayName: string;
  totalDeliveries: number;
  successRate: number;
  avgRating: number;
};

@Component({
  selector: 'app-delivery-tracking',
  standalone: false,
  templateUrl: './delivery-tracking.component.html',
  styleUrls: ['./delivery-tracking.component.css']
})
export class DeliveryTrackingComponent implements OnInit, OnDestroy, AfterViewInit {
  @ViewChild('mapContainer', { static: false }) mapContainer?: ElementRef;

  role = (localStorage.getItem('role') || localStorage.getItem('userRole') || 'Client').toLowerCase();
  private currentUserId = this.requestService.getCurrentUserId();
  showAllStatusOption = true;

  statuses: DeliveryStatus[] = ['En attente', 'En cours', 'Livrée', 'Refusée'];
  selectedStatus: DeliveryStatus | 'Tous' = 'Tous';
  searchText = '';

  deliveries: TrackingItem[] = [];

  selectedId = '';
  notificationDeliveryId = '';
  notification: TrackingNotification | null = null;
  showDeleteDialog = false;
  pendingDeleteDelivery: TrackingItem | null = null;
  deleteInProgress = false;
  selectedRating = 5;
  ratingInProgress = false;
  selectedTransporterProfile: TransporterProfile | null = null;
  simulationRunning = false;
  simulationProgress = 0;

  private simulationTimerId: number | null = null;

  constructor(
    private mapService: DeliveryMapService,
    private requestService: DeliveryRequestService,
    private router: Router,
    private route: ActivatedRoute
  ) {}

  ngOnInit(): void {
    const isTransporter = this.role === 'transporteur' || this.role === 'transporter' || this.role.includes('transport');
    if (isTransporter) {
      this.router.navigate(['/delivery/active']);
      return;
    }

    this.loadDeliveries();
    this.route.queryParamMap.subscribe((params) => {
      this.notificationDeliveryId = params.get('deliveryId') || '';
      if (this.notificationDeliveryId) {
        this.selectedId = this.notificationDeliveryId;
        this.selectedStatus = 'Tous';
      }
      this.renderDeliveryRoute();
    });

    this.requestService.refreshFromBackend().subscribe(() => {
      this.loadDeliveries();
      this.selectedId = this.filteredDeliveries.find((delivery) => delivery.id === this.notificationDeliveryId)?.id
        || this.filteredDeliveries[0]?.id
        || '';
      this.renderDeliveryRoute();
    });
    this.showAllStatusOption = true;
    if (this.isFarmer()) {
      this.selectedStatus = 'Tous';
    }

    this.selectedId = this.filteredDeliveries.find((delivery) => delivery.id === this.notificationDeliveryId)?.id
      || this.filteredDeliveries[0]?.id
      || '';
  }

  ngAfterViewInit(): void {
    // Ensure map container is mounted before any marker rendering.
    this.initializeMap();
  }

  ngOnDestroy(): void {
    this.stopSimulation();
    this.mapService.destroy();
  }


  private initializeMap(): void {
    if (!this.mapContainer) return;

    const delivery = this.selectedDelivery;
    const hasPickup = Boolean(delivery?.pickupLat && delivery?.pickupLng);
    const centerLat = hasPickup
      ? ((delivery!.pickupLat as number) + ((delivery!.dropoffLat as number) || (delivery!.pickupLat as number))) / 2
      : 36.8065;
    const centerLng = hasPickup
      ? ((delivery!.pickupLng as number) + ((delivery!.dropoffLng as number) || (delivery!.pickupLng as number))) / 2
      : 10.1815;

    this.mapService.initMap(this.mapContainer.nativeElement, centerLat, centerLng, 10);
    this.renderDeliveryRoute();
  }

  private renderDeliveryRoute(): void {
    const delivery = this.selectedDelivery;
    if (!delivery) return;

    if (!this.mapService.getMap()) {
      this.initializeMap();
      if (!this.mapService.getMap()) {
        return;
      }
    }

    this.mapService.clear();

    if (delivery.pickupLat && delivery.pickupLng) {
      this.mapService.addMarker(
        delivery.pickupLat,
        delivery.pickupLng,
        `<strong>Départ:</strong> ${delivery.pickup}`,
        {
          title: 'Départ',
          zIndexOffset: 1000,
          icon: this.mapService.getPointIcon('start')
        }
      );
    }

    if (delivery.dropoffLat && delivery.dropoffLng) {
      this.mapService.addMarker(
        delivery.dropoffLat,
        delivery.dropoffLng,
        `<strong>Destination:</strong> ${delivery.dropoff}`,
        {
          title: 'Destination',
          zIndexOffset: 1000,
          icon: this.mapService.getPointIcon('end')
        }
      );
    }

    if (delivery.currentLat && delivery.currentLng && delivery.status === 'En cours') {
      this.mapService.addCircleMarker(delivery.currentLat, delivery.currentLng, 10, '#FF9800');
    }

    const routePoints = this.resolveRoutePoints(delivery);

    if (routePoints.length >= 2) {
      // Use OSRM for real road routing
      this.mapService.drawRouteOSRM(routePoints, '#4caf50', 5).then(() => {
        this.mapService.fitBounds(routePoints, 80);
      });
      this.mapService.getRouteGuidance(routePoints).then((guidance) => {
        if (!guidance) {
          return;
        }
        const selected = this.deliveries.find((item) => item.id === delivery.id);
        if (selected) {
          selected.etaMinutes = guidance.etaMinutes;
        }
      });
    }
  }

  get selectedDelivery(): TrackingItem | undefined {
    const source = this.filteredDeliveries;
    const selected = source.find((d) => d.id === this.selectedId);
    return selected || source[0];
  }

  get filteredDeliveries(): TrackingItem[] {
    const q = this.searchText.trim().toLowerCase();
    return this.deliveries.filter((d) => {
      const ownerOk = !this.isFarmer() || d.ownerId === this.currentUserId;
      const matchStatus = this.selectedStatus === 'Tous' || d.status === this.selectedStatus;
      const matchSearch = !q || (d.reference + ' ' + d.product + ' ' + d.pickup + ' ' + d.dropoff).toLowerCase().includes(q);
      return ownerOk && matchStatus && matchSearch;
    });
  }

  selectDelivery(id: string): void {
    this.selectedId = id;

    const delivery = this.selectedDelivery;
    if (!delivery || !delivery.pickupLat || !delivery.pickupLng) return;

    const map = this.mapService.getMap();
    if (!map) {
      this.initializeMap();
      return;
    }

    this.renderDeliveryRoute();
  }

  openDeliveryDetail(id: string, event?: Event): void {
    event?.stopPropagation();
    this.router.navigate(['/delivery/livraisons', id]);
  }

  editSelectedDelivery(): void {
    const delivery = this.selectedDelivery;
    if (!delivery) return;

    if (!this.canManageDelivery(delivery)) {
      this.pushNotification(
        'error',
        'Modification indisponible',
        'Une demande déjà acceptée par un livreur ne peut plus être modifiée.'
      );
      return;
    }

    this.router.navigate(['/delivery/livraisons', delivery.id, 'edit']);
  }

  deleteSelectedDelivery(): void {
    const delivery = this.selectedDelivery;
    if (!delivery) return;

    if (!this.canManageDelivery(delivery)) {
      this.pushNotification(
        'error',
        'Suppression indisponible',
        'Une demande déjà acceptée par un livreur ne peut plus être supprimée.'
      );
      return;
    }

    this.pendingDeleteDelivery = delivery;
    this.showDeleteDialog = true;
  }

  canShowRatingPanel(delivery?: TrackingItem): boolean {
    if (!delivery || !this.isFarmer() || delivery.ownerId !== this.currentUserId) {
      return false;
    }
    if (delivery.status !== 'Livrée') {
      return false;
    }
    if ((delivery.rating || 0) > 0) {
      return false;
    }
    return delivery.ratingStatus !== 'IGNORED';
  }

  canShowRatedInfo(delivery?: TrackingItem): boolean {
    return Boolean(delivery && (delivery.rating || 0) > 0 && delivery.ownerId === this.currentUserId);
  }

  getFarmerDisplayName(delivery?: TrackingItem): string {
    if (delivery?.farmerName) {
      return delivery.farmerName;
    }
    return 'Agriculteur';
  }

  getTransporterDisplayName(delivery?: TrackingItem): string {
    if (delivery?.transporterName) {
      return delivery.transporterName;
    }
    return 'Transporteur non assigne';
  }

  canOpenTransporterProfile(delivery?: TrackingItem): boolean {
    return Boolean(delivery?.transporterId && delivery.transporterId > 0);
  }

  openTransporterProfile(delivery?: TrackingItem): void {
    const transporterId = delivery?.transporterId || 0;
    if (!transporterId) {
      return;
    }

    const related = this.requestService.getAll().filter((item) => item.acceptedById === transporterId);
    const delivered = related.filter((item) => item.status === 'Livrée');
    const rated = delivered.filter((item) => Number(item.rating || 0) > 0);
    const successRate = related.length > 0 ? this.round2((delivered.length * 100) / related.length) : 0;
    const avgRating = rated.length > 0
      ? rated.reduce((sum, item) => sum + Number(item.rating || 0), 0) / rated.length
      : 0;

    this.selectedTransporterProfile = {
      displayName: this.getTransporterDisplayName(delivery),
      totalDeliveries: related.length,
      successRate,
      avgRating: this.round2(avgRating)
    };
  }

  closeTransporterProfile(): void {
    this.selectedTransporterProfile = null;
  }

  selectRating(value: number): void {
    if (value < 1 || value > 5 || this.ratingInProgress) {
      return;
    }
    this.selectedRating = value;
  }

  launchTrackingSimulation(): void {
    const delivery = this.selectedDelivery;
    if (!delivery || this.simulationRunning) {
      return;
    }

    this.stopSimulation();
    this.simulationRunning = true;
    this.simulationProgress = 0;

    const startLat = delivery.currentLat ?? delivery.pickupLat ?? 0;
    const startLng = delivery.currentLng ?? delivery.pickupLng ?? 0;
    const endLat = delivery.dropoffLat ?? startLat;
    const endLng = delivery.dropoffLng ?? startLng;

    this.simulationTimerId = window.setInterval(() => {
      if (!this.simulationRunning) {
        return;
      }

      this.simulationProgress = Math.min(100, this.simulationProgress + 20);
      const ratio = this.simulationProgress / 100;
      const lat = startLat + (endLat - startLat) * ratio;
      const lng = startLng + (endLng - startLng) * ratio;

      this.requestService.updateCurrentPosition(delivery.id, lat, lng).subscribe();

      if (this.simulationProgress >= 100) {
        this.stopSimulation();
      }
    }, 1000);
  }

  stopSimulation(): void {
    this.simulationRunning = false;
    if (this.simulationTimerId !== null) {
      window.clearInterval(this.simulationTimerId);
      this.simulationTimerId = null;
    }
  }

  submitRating(): void {
    const delivery = this.selectedDelivery;
    if (!delivery || !this.canShowRatingPanel(delivery) || this.ratingInProgress) {
      return;
    }

    this.ratingInProgress = true;
    this.requestService.evaluerTransporteur(delivery.id, this.selectedRating, this.currentUserId).subscribe((updated) => {
      this.ratingInProgress = false;
      if (!updated) {
        this.pushNotification('error', 'Notation impossible', 'La note n a pas pu etre enregistree.');
        return;
      }

      this.pushNotification('success', 'Merci pour votre note', `Vous avez note ce livreur ${this.selectedRating}/5.`);
      this.reloadDeliveries();
    });
  }

  ignoreRatingPrompt(): void {
    const delivery = this.selectedDelivery;
    if (!delivery || !this.canShowRatingPanel(delivery) || this.ratingInProgress) {
      return;
    }

    this.ratingInProgress = true;
    this.requestService.ignorerNotationTransporteur(delivery.id, this.currentUserId).subscribe((updated) => {
      this.ratingInProgress = false;
      if (!updated) {
        this.pushNotification('error', 'Action impossible', 'Impossible d ignorer cette interface pour le moment.');
        return;
      }

      this.pushNotification('info', 'Notation ignoree', 'Vous pouvez continuer sans noter ce livreur.');
      this.reloadDeliveries();
    });
  }

  closeDeleteDialog(): void {
    if (this.deleteInProgress) {
      return;
    }

    this.showDeleteDialog = false;
    this.pendingDeleteDelivery = null;
  }

  confirmDelete(): void {
    const delivery = this.pendingDeleteDelivery;
    if (!delivery || this.deleteInProgress) {
      return;
    }

    this.deleteInProgress = true;

    this.requestService.deleteApiDelivery(delivery.id).subscribe((deleted) => {
      this.deleteInProgress = false;
      this.showDeleteDialog = false;
      this.pendingDeleteDelivery = null;

      if (!deleted) {
        this.pushNotification(
          'error',
          'Suppression impossible',
          'La demande a peut-être déjà été acceptée par un livreur. La liste a été rechargée.'
        );
        this.reloadDeliveries();
        return;
      }

      this.pushNotification(
        'success',
        'Demande supprimée',
        `La demande ${delivery.reference} a été supprimée avec succès.`
      );
      this.reloadDeliveries();
    });
  }

  canManageSelectedDelivery(): boolean {
    return this.canManageDelivery(this.selectedDelivery);
  }

  trackIsActive(item: TrackingItem): boolean {
    return item.id === this.selectedId;
  }

  isFarmer(): boolean {
    return this.role === 'agriculteur' || this.role === 'farmer' || this.role.includes('agric');
  }

  private canManageDelivery(delivery?: TrackingItem): boolean {
    return Boolean(
      delivery &&
      this.isFarmer() &&
      delivery.ownerId === this.currentUserId &&
      delivery.realStatus === 'En attente'
    );
  }

  private loadDeliveries(): void {
    const requests = this.requestService.getAll();
    this.deliveries = requests.map((r) => {
      const inProgress = r.status === 'En cours';
      const delivered = r.status === 'Livrée';
      const accepted = r.status === 'Acceptée';
      const displayStatus: DeliveryStatus = accepted ? 'En attente' : (r.status as DeliveryStatus);
      return {
        id: r.id,
        reference: r.reference,
        product: r.product,
        status: displayStatus,
        realStatus: r.status as DeliveryStatus,
        pickup: r.pickupLabel,
        dropoff: r.dropoffLabel,
        pickupLat: r.pickupLat,
        pickupLng: r.pickupLng,
        dropoffLat: r.dropoffLat,
        dropoffLng: r.dropoffLng,
        currentLat: r.currentLat || (inProgress ? (r.pickupLat + r.dropoffLat) / 2 : delivered ? r.dropoffLat : undefined),
        currentLng: r.currentLng || (inProgress ? (r.pickupLng + r.dropoffLng) / 2 : delivered ? r.dropoffLng : undefined),
        progress: delivered ? 100 : inProgress ? 52 : 0,
        etaMinutes: delivered ? 0 : inProgress ? 45 : 0,
        ownerId: r.createdById,
        farmerId: r.createdById,
        transporterId: r.acceptedById,
        farmerName: this.formatPersonName(r.createdByEmail, 'Agriculteur', r.createdById),
        transporterName: this.formatPersonName(r.acceptedByEmail, 'Transporteur', r.acceptedById),
        rating: r.rating,
        ratingStatus: r.ratingStatus,
        hasLivePosition: Boolean(r.currentLat && r.currentLng)
      };
    });
  }

  private resolveRoutePoints(delivery: TrackingItem): { lat: number; lng: number }[] {
    if (delivery.status === 'En cours' && delivery.currentLat && delivery.currentLng && delivery.pickupLat && delivery.pickupLng) {
      return [
        { lat: delivery.currentLat, lng: delivery.currentLng },
        { lat: delivery.pickupLat, lng: delivery.pickupLng }
      ];
    }

    const points: { lat: number; lng: number }[] = [];
    if (delivery.pickupLat && delivery.pickupLng) {
      points.push({ lat: delivery.pickupLat, lng: delivery.pickupLng });
    }
    if (delivery.dropoffLat && delivery.dropoffLng) {
      points.push({ lat: delivery.dropoffLat, lng: delivery.dropoffLng });
    }
    return points;
  }

  private reloadDeliveries(): void {
    this.requestService.refreshFromBackend().subscribe(() => {
      this.loadDeliveries();
      this.selectedId = this.filteredDeliveries.find((delivery) => delivery.id === this.selectedId)?.id
        || this.filteredDeliveries[0]?.id
        || '';
      this.renderDeliveryRoute();
    });
  }

  private pushNotification(type: TrackingNotification['type'], title: string, message: string): void {
    this.notification = { type, title, message };
    window.setTimeout(() => (this.notification = null), 3500);
  }

  private round2(value: number): number {
    return Math.round(value * 100) / 100;
  }

  private formatPersonName(email?: string, fallbackRole: 'Agriculteur' | 'Transporteur' = 'Agriculteur', id?: number): string {
    if (email && email.includes('@')) {
      const localPart = email.split('@')[0];
      const normalized = localPart
        .replace(/[-_.]+/g, ' ')
        .replace(/\b(transporter|transporteur|farmer|agriculteur)\b/gi, '')
        .replace(/\s+/g, ' ')
        .replace(/\b\w/g, (letter) => letter.toUpperCase())
        .trim();
      if (normalized) {
        return normalized;
      }
    }
    return fallbackRole;
  }
}

/**
 * Helpers to read the current user's identity from the shared auth storage
 * used by AgricultureFront's AuthService (key: 'authUser').
 *
 * The delivery module was originally standalone and kept role/id/email in
 * separate localStorage keys ('role', 'userRole', 'currentUserId', ...).
 * After integration into AgricultureFront these helpers bridge the gap
 * without touching any code outside the delivery module.
 */

interface StoredAuthUser {
  userId: number;
  username: string;
  email: string;
  role: string;
}

function readAuthUser(): StoredAuthUser | null {
  const raw = localStorage.getItem('authUser');
  if (!raw) return null;
  try {
    return JSON.parse(raw) as StoredAuthUser;
  } catch {
    return null;
  }
}

/** Returns the current user's role as a lowercase string (e.g. 'agriculteur', 'transporteur', 'admin'). */
export function getDeliveryUserRole(): string {
  return readAuthUser()?.role?.toLowerCase() ?? 'client';
}

/** Returns the current user's numeric id, or null if not logged in. */
export function getDeliveryUserId(): number | null {
  const user = readAuthUser();
  return user?.userId ?? null;
}

/** Returns the current user's email, lower-cased. Falls back to 'unknown@local'. */
export function getDeliveryUserEmail(): string {
  return readAuthUser()?.email?.toLowerCase() ?? 'unknown@local';
}

/**
 * Helpers to read the current user's identity from the shared auth storage
 * used by AgricultureFront's AuthService (key: 'authUser').
 *
 * The delivery module was originally standalone and kept role/id/email in
 * separate localStorage keys ('role', 'userRole', 'currentUserId', ...).
 * After integration into AgricultureFront these helpers bridge the gap
 * without touching any code outside the delivery module.
 */

interface StoredAuthUser {
  userId: number;
  username: string;
  email: string;
  role?: string;
  roles?: string[];
}

function readAuthUser(): StoredAuthUser | null {
  const raw = localStorage.getItem('authUser');
  if (!raw) return null;
  try {
    return JSON.parse(raw) as StoredAuthUser;
  } catch {
    return null;
  }
}

/** Returns the current user's role as a lowercase string (e.g. 'agriculteur', 'transporteur', 'admin'). */
export function getDeliveryUserRole(): string {
  const authUser = readAuthUser();
  const authRole = authUser?.role;
  if (authRole && typeof authRole === 'string') {
    return authRole.trim().toLowerCase();
  }

  const authRoles = authUser?.roles;
  if (Array.isArray(authRoles) && authRoles.length > 0) {
    return String(authRoles[0]).trim().toLowerCase();
  }

  const roleFallback = localStorage.getItem('userRole') || localStorage.getItem('role');
  return roleFallback?.trim().toLowerCase() || 'client';
}

/** Returns the current user's numeric id, or null if not logged in. */
export function getDeliveryUserId(): number | null {
  const user = readAuthUser();
  return user?.userId ?? null;
}

/** Returns the current user's email, lower-cased. Falls back to 'unknown@local'. */
export function getDeliveryUserEmail(): string {
  return readAuthUser()?.email?.toLowerCase() ?? 'unknown@local';
}

import { Injectable } from '@angular/core';
import { HttpClient, HttpParams } from '@angular/common/http';
import { Observable, catchError, map, of, switchMap, tap } from 'rxjs';
import { getDeliveryUserEmail, getDeliveryUserId, getDeliveryUserRole } from './delivery-auth.helper';

export type DeliveryRequestStatus = 'En attente' | 'Acceptée' | 'En cours' | 'Livrée' | 'Refusée';

export type DeliveryRequest = {
  id: string;
  reference: string;
  product: string;
  weightKg: number;
  details: string;
  pickupLabel: string;
  dropoffLabel: string;
  estimatedPrice: number;
  pickupLat: number;
  pickupLng: number;
  dropoffLat: number;
  dropoffLng: number;
  autoGrouping: boolean;
  status: DeliveryRequestStatus;
  createdByRole: 'Agriculteur' | 'Transporteur';
  createdByEmail: string;
  createdById?: number;
  acceptedByEmail?: string;
  acceptedById?: number;
  createdAt: string;
  departureDate?: string;
  plannedDeliveryDate?: string;
  deliveredAt?: string;
  grouped?: boolean;
  groupReference?: string;
  rating?: number;
  ratingStatus?: 'PENDING' | 'RATED' | 'IGNORED';
  currentLat?: number;
  currentLng?: number;
  signatureStatus?: string;
};

export type DeliveryRequestInput = {
  reference: string;
  product: string;
  weightKg: number;
  details: string;
  departureDate?: string;
  pickupLabel: string;
  dropoffLabel: string;
  estimatedPrice: number;
  pickupLat: number;
  pickupLng: number;
  dropoffLat: number;
  dropoffLng: number;
  autoGrouping: boolean;
};

export type FarmerKnownTransporter = {
  transporteurId: number;
  displayName: string;
  completedDeliveries: number;
  lastDeliveryAt?: string;
};

export type TargetedCreateResult = {
  delivery: DeliveryRequest | null;
  errorMessage?: string;
};

export type DeliveryPriceEstimate = {
  estimatedPrice: number;
  distanceKm: number;
  durationHours: number;
  weatherSurchargePercent: number;
  weatherCondition: string;
};

export type LivraisonApi = {
  id: number;
  reference: string;
  type?: string;
  status?: string;
  statusDemande?: string;
  agriculteurId: number;
  transporteurId: number;
  dateCreation?: string;
  dateDepart?: string;
  datePreferenceAgriculteur?: string;
  dateProposeeNegociation?: string;
  dateLivraisonPrevue?: string;
  dateLivraisonEffective?: string;
  adresseDepart?: string;
  adresseArrivee?: string;
  latDepart?: number;
  lngDepart?: number;
  latArrivee?: number;
  lngArrivee?: number;
  latActuelle?: number;
  lngActuelle?: number;
  poids?: number;
  volume?: number;
  typeProduit?: string;
  detailsDemande?: string;
  estRegroupable?: boolean;
  prix?: number;
  note?: number;
  ratingStatus?: string;
  grouped?: boolean;
  groupReference?: string;
  signatureStatus?: string;
  signatureData?: string;
  signedAt?: string;
};

export type AcceptTransporterResult = {
  success: boolean;
  delivery?: LivraisonApi | null;
  errorMessage?: string;
};

export type DeliveryAdminKpis = {
  total: number;
  enAttente: number;
  acceptees: number;
  enCours: number;
  livre: number;
  annulees: number;
  revenue: number;
  avgPrice: number;
  tauxLivraison: number;
};

@Injectable()
export class DeliveryRequestService {
  private readonly storageKey = 'deliveryRequests';
  private readonly usersDirectoryKey = 'deliveryKnownUsers';
  private readonly apiBase = '/livraison/api/livraisons';

  constructor(private http: HttpClient) {
    this.captureCurrentUserIdentity();
  }

  getCurrentUserEmail(): string {
    return getDeliveryUserEmail();
  }

  getCurrentUserId(): number {
    return getDeliveryUserId() ?? 0;
  }

  getAdminKpis(): Observable<DeliveryAdminKpis> {
    return this.http.get<Record<string, unknown>>(`${this.apiBase}/admin/kpis`).pipe(
      map((payload) => this.normalizeAdminKpis(payload)),
      catchError((err) => {
        console.warn('Load admin KPIs failed, using computed fallback.', err);
        return of(this.emptyAdminKpis());
      })
    );
  }

  refreshFromBackend(): Observable<DeliveryRequest[]> {
    let params = new HttpParams();
    if (this.isFarmerRole()) {
      params = params.set('agriculteurId', String(this.getCurrentUserId()));
    }

    return this.http.get<LivraisonApi[]>(this.apiBase, { params }).pipe(
      map((items) => items.map((x) => this.fromApi(x))),
      tap((mapped) => this.writeToStorage(mapped)),
      catchError((err) => {
        console.warn('Delivery refresh failed, clearing local cache to avoid stale UI.', err);
        this.writeToStorage([]);
        return of([]);
      })
    );
  }

  getApiById(requestId: string): Observable<LivraisonApi | null> {
    const numericId = this.toNumericId(requestId);
    if (!numericId) {
      return of(null);
    }

    return this.http.get<LivraisonApi>(`${this.apiBase}/${numericId}`).pipe(
      tap((api) => this.upsertFromApi(api)),
      catchError((err) => {
        console.warn('Load livraison by id failed.', err);
        return of(null);
      })
    );
  }

  createApiDelivery(payload: Partial<LivraisonApi>): Observable<LivraisonApi | null> {
    return this.http.post<LivraisonApi>(this.apiBase, payload).pipe(
      tap((saved) => this.upsertFromApi(saved)),
      catchError((err) => {
        console.warn('Create livraison failed.', err);
        return of(null);
      })
    );
  }

  updateApiDelivery(requestId: string, payload: Partial<LivraisonApi>): Observable<LivraisonApi | null> {
    const numericId = this.toNumericId(requestId);
    if (!numericId) {
      return of(null);
    }

    return this.http.put<LivraisonApi>(`${this.apiBase}/${numericId}`, payload).pipe(
      tap((updated) => this.upsertFromApi(updated)),
      catchError((err) => {
        console.warn('Update livraison failed.', err);
        return of(null);
      })
    );
  }

  deleteApiDelivery(requestId: string): Observable<boolean> {
    const numericId = this.toNumericId(requestId);
    if (!numericId) {
      return of(false);
    }

    return this.http.delete<void>(`${this.apiBase}/${numericId}`).pipe(
      tap(() => this.removeFromStorage(String(numericId))),
      map(() => true),
      catchError((err) => {
        console.warn('Delete livraison failed.', err);
        return of(false);
      })
    );
  }

  assignTransporteur(requestId: string, transporteurId: number): Observable<LivraisonApi | null> {
    const numericId = this.toNumericId(requestId);
    if (!numericId || !transporteurId) {
      return of(null);
    }

    return this.http.put<LivraisonApi>(`${this.apiBase}/${numericId}/assign`, null, {
      params: new HttpParams().set('transporteurId', String(transporteurId))
    }).pipe(
      tap((updated) => this.upsertFromApi(updated)),
      catchError((err) => {
        console.warn('Assign transporteur failed.', err);
        return of(null);
      })
    );
  }

  updateCurrentPosition(requestId: string, lat: number, lng: number): Observable<LivraisonApi | null> {
    const numericId = this.toNumericId(requestId);
    if (!numericId || !Number.isFinite(lat) || !Number.isFinite(lng)) {
      return of(null);
    }

    return this.http.put<LivraisonApi>(`${this.apiBase}/${numericId}/gps`, null, {
      params: new HttpParams()
        .set('lat', String(lat))
        .set('lng', String(lng))
    }).pipe(
      tap((updated) => this.upsertFromApi(updated)),
      catchError((err) => {
        console.warn('Update GPS failed.', err);
        return of(null);
      })
    );
  }

  evaluerTransporteur(requestId: string, note: number, evaluateurId?: number): Observable<LivraisonApi | null> {
    const numericId = this.toNumericId(requestId);
    if (!numericId || !Number.isFinite(note)) {
      return of(null);
    }

    let params = new HttpParams().set('note', String(note));
    if (evaluateurId) {
      params = params.set('evaluateurId', String(evaluateurId));
    }

    return this.http.put<LivraisonApi>(`${this.apiBase}/${numericId}/note`, null, { params }).pipe(
      tap((updated) => this.upsertFromApi(updated)),
      catchError((err) => {
        console.warn('Evaluation transporteur failed.', err);
        return of(null);
      })
    );
  }

  ignorerNotationTransporteur(requestId: string, agriculteurId?: number): Observable<LivraisonApi | null> {
    const numericId = this.toNumericId(requestId);
    const ownerId = agriculteurId || this.getCurrentUserId();
    if (!numericId || !ownerId) {
      return of(null);
    }

    return this.http.post<LivraisonApi>(`${this.apiBase}/${numericId}/rating/ignore`, null, {
      params: new HttpParams().set('agriculteurId', String(ownerId))
    }).pipe(
      tap((updated) => this.upsertFromApi(updated)),
      catchError((err) => {
        console.warn('Ignore rating failed.', err);
        return of(null);
      })
    );
  }

  saveSignature(requestId: string | number, signatureData: string, agriculteurId?: number): Observable<LivraisonApi | null> {
    const numericId = typeof requestId === 'number' ? requestId : this.toNumericId(requestId);
    const ownerId = agriculteurId || this.getCurrentUserId();
    if (!numericId || !ownerId) {
      return of(null);
    }

    return this.http.post<LivraisonApi>(
      `${this.apiBase}/${numericId}/signature`,
      { signatureData },
      { params: new HttpParams().set('agriculteurId', String(ownerId)) }
    ).pipe(
      tap((updated) => this.upsertFromApi(updated)),
      catchError((err) => {
        console.warn('Save signature failed.', err);
        return of(null);
      })
    );
  }

  getAll(): DeliveryRequest[] {
    const parsed = this.readFromStorage();
    return parsed.sort((a, b) => (a.createdAt < b.createdAt ? 1 : -1));
  }

  getPendingFarmerRequests(): DeliveryRequest[] {
    return this.getAll().filter(
      (r) => r.createdByRole === 'Agriculteur' && r.status === 'En attente'
    );
  }

  getForCurrentFarmer(): DeliveryRequest[] {
    const userId = this.getCurrentUserId();
    return this.getAll().filter(
      (r) => r.createdByRole === 'Agriculteur' && r.createdById === userId
    );
  }

  getInProgressForCurrentFarmer(): DeliveryRequest[] {
    return this.getForCurrentFarmer().filter((r) => r.status === 'En cours');
  }

  getById(requestId: string): DeliveryRequest | null {
    return this.getAll().find((r) => r.id === requestId) || null;
  }

  getTransporterActiveRequests(): DeliveryRequest[] {
    const userId = this.getCurrentUserId();
    return this.getAll().filter(
      (r) => r.acceptedById === userId && (r.status === 'Acceptée' || r.status === 'En cours')
    );
  }

  getTransporterInProgressRequests(): DeliveryRequest[] {
    const userId = this.getCurrentUserId();
    return this.getAll().filter((r) => r.acceptedById === userId && r.status === 'En cours');
  }

  getTransporterHistoryRequests(): DeliveryRequest[] {
    const userId = this.getCurrentUserId();
    return this.getAll().filter((r) => r.acceptedById === userId && r.status === 'Livrée');
  }

  getTransporterTimelineRequests(): DeliveryRequest[] {
    const userId = this.getCurrentUserId();
    return this.getAll().filter(
      (r) => r.acceptedById === userId && (r.status === 'Acceptée' || r.status === 'En cours' || r.status === 'Livrée')
    );
  }

  getFarmerTimelineRequests(): DeliveryRequest[] {
    return this.getForCurrentFarmer().filter(
      (r) => r.status === 'Acceptée' || r.status === 'En cours' || r.status === 'Livrée'
    );
  }

  getTransporterCalendarRequests(): DeliveryRequest[] {
    const userId = this.getCurrentUserId();
    return this.getAll().filter(
      (r) => r.acceptedById === userId && (r.status === 'Acceptée' || r.status === 'En cours' || r.status === 'Livrée')
    );
  }

  acceptByCurrentTransporter(requestId: string): Observable<AcceptTransporterResult> {
    const numericId = this.toNumericId(requestId);
    const transporterId = this.getCurrentUserId();
    const previous = this.getById(requestId);

    if (!numericId) {
      return of({
        success: false,
        errorMessage: 'Identifiant de livraison invalide.'
      });
    }

    // Optimistic UI update
    this.updateRequest(requestId, {
      status: 'Acceptée',
      acceptedById: transporterId,
      acceptedByEmail: this.getCurrentUserEmail()
    });

    return this.http.put<LivraisonApi>(`${this.apiBase}/${numericId}/assign`, null, {
      params: new HttpParams().set('transporteurId', String(transporterId))
    }).pipe(
      tap((updated) => this.upsertFromApi(updated)),
      switchMap((assigned) => this.http.put<LivraisonApi>(`${this.apiBase}/${numericId}/status`, null, {
        params: new HttpParams().set('status', 'ACCEPTEE')
      }).pipe(
        tap((updated) => this.upsertFromApi(updated)),
        catchError((err) => {
          console.warn('Accept transporter status sync failed after assign.', err);
          return of(assigned);
        })
      )),
      map((updated) => ({
        success: true,
        delivery: updated
      })),
      catchError((err) => {
        console.warn('Accept transporter backend sync failed.', err);
        if (previous) {
          this.updateRequest(requestId, {
            status: previous.status,
            acceptedById: previous.acceptedById,
            acceptedByEmail: previous.acceptedByEmail
          });
        }
        return of({
          success: false,
          errorMessage: this.extractBackendErrorMessage(err)
        });
      })
    );
  }

  startRouteToPickup(requestId: string): Observable<AcceptTransporterResult> {
    const numericId = this.toNumericId(requestId);
    const transporterId = this.getCurrentUserId();
    if (!numericId || !transporterId) {
      return of({ success: false, errorMessage: 'Identifiant de livraison invalide.' });
    }

    const blockingRequest = this.getTransporterInProgressRequests().find((r) => r.id !== requestId);
    if (blockingRequest) {
      return of({
        success: false,
        errorMessage: `Vous avez deja une livraison en cours (${blockingRequest.reference}). Terminez-la ou annulez-la avant d'en commencer une autre.`
      });
    }

    return this.http.post<LivraisonApi>(`${this.apiBase}/${numericId}/start-route`, null, {
      params: new HttpParams().set('transporteurId', String(transporterId))
    }).pipe(
      tap((updated) => this.upsertFromApi(updated)),
      map((updated) => ({ success: true, delivery: updated })),
      catchError((err) => {
        console.warn('Start route backend sync failed.', err);
        return of({ success: false, errorMessage: this.extractBackendErrorMessage(err) });
      })
    );
  }

  createFromFarmer(input: DeliveryRequestInput): Observable<DeliveryRequest | null> {
    const currentUserId = this.getCurrentUserId();
    const payload = {
      reference: input.reference,
      type: this.toBackendTypeByWeight(input.weightKg),
      status: 'EN_ATTENTE',
      agriculteurId: currentUserId,
      transporteurId: 0,
      dateDepart: input.departureDate ? this.toDateTimePayload(input.departureDate) : undefined,
      datePreferenceAgriculteur: input.departureDate ? this.toDateTimePayload(input.departureDate) : undefined,
      adresseDepart: input.pickupLabel,
      adresseArrivee: input.dropoffLabel,
      latDepart: input.pickupLat,
      lngDepart: input.pickupLng,
      latArrivee: input.dropoffLat,
      lngArrivee: input.dropoffLng,
      poids: input.weightKg,
      typeProduit: input.product,
      detailsDemande: input.details,
      estRegroupable: input.autoGrouping,
      prix: input.estimatedPrice
    };

    return this.createApiDelivery(payload).pipe(
      map((saved) => (saved ? this.fromApi(saved) : null))
    );
  }

  getPreferredTransportersForCurrentFarmer(): Observable<FarmerKnownTransporter[]> {
    const agriculteurId = this.getCurrentUserId();
    if (!agriculteurId) {
      return of([]);
    }

    return this.http.get<FarmerKnownTransporter[]>(`${this.apiBase}/agriculteur/${agriculteurId}/transporteurs-preferes`).pipe(
      map((items) => Array.isArray(items) ? items : []),
      catchError((err) => {
        console.warn('Load preferred transporters failed.', err);
        return of([]);
      })
    );
  }

  createFromFarmerToTransporter(input: DeliveryRequestInput, transporteurId: number): Observable<TargetedCreateResult> {
    const agriculteurId = this.getCurrentUserId();
    if (!agriculteurId || !transporteurId) {
      return of({
        delivery: null,
        errorMessage: 'Transporteur invalide.'
      });
    }

    const payload = {
      reference: input.reference,
      product: input.product,
      weightKg: input.weightKg,
      details: input.details,
      departureDate: input.departureDate ? this.toDateTimePayload(input.departureDate) : undefined,
      pickupLabel: input.pickupLabel,
      dropoffLabel: input.dropoffLabel,
      estimatedPrice: input.estimatedPrice,
      pickupLat: input.pickupLat,
      pickupLng: input.pickupLng,
      dropoffLat: input.dropoffLat,
      dropoffLng: input.dropoffLng,
      autoGrouping: input.autoGrouping,
      transporteurId
    };

    return this.http.post<LivraisonApi>(`${this.apiBase}/agriculteur/${agriculteurId}/livraisons/cibler-transporteur`, payload).pipe(
      tap((saved) => this.upsertFromApi(saved)),
      map((saved) => ({
        delivery: saved ? this.fromApi(saved) : null
      })),
      catchError((err) => {
        console.warn('Create targeted delivery failed.', err);
        return of({
          delivery: null,
          errorMessage: this.extractBackendErrorMessage(err)
        });
      })
    );
  }

  estimateDeliveryPrice(input: {
    pickupLat: number;
    pickupLng: number;
    dropoffLat: number;
    dropoffLng: number;
    weightKg: number;
    autoGrouping: boolean;
    distanceKm?: number;
    durationHours?: number;
  }): Observable<DeliveryPriceEstimate | null> {
    const payload = {
      pickupLat: input.pickupLat,
      pickupLng: input.pickupLng,
      dropoffLat: input.dropoffLat,
      dropoffLng: input.dropoffLng,
      weightKg: input.weightKg,
      autoGrouping: input.autoGrouping,
      distanceKm: input.distanceKm,
      durationHours: input.durationHours
    };

    return this.http.post<DeliveryPriceEstimate>(`${this.apiBase}/pricing/estimate`, payload).pipe(
      map((estimate) => estimate || null),
      catchError((err) => {
        console.warn('Estimate delivery price failed.', err);
        return of(null);
      })
    );
  }

  updateStatus(requestId: string, status: DeliveryRequestStatus): void {
    this.updateStatusApi(requestId, status).subscribe();
  }

  updateStatusApi(requestId: string, status: DeliveryRequestStatus): Observable<LivraisonApi | null> {
    this.updateRequest(requestId, { status });

    const numericId = this.toNumericId(requestId);
    if (!numericId) {
      return of(null);
    }

    return this.http.put<LivraisonApi>(`${this.apiBase}/${numericId}/status`, null, {
      params: new HttpParams().set('status', this.toBackendStatus(status))
    }).pipe(
      tap((updated) => this.upsertFromApi(updated)),
      catchError((err) => {
        console.warn('Update status backend sync failed.', err);
        return of(null);
      })
    );
  }

  updateRequest(requestId: string, patch: Partial<DeliveryRequest>): void {
    const requests = this.readFromStorage();
    const updated = requests.map((r) => (r.id === requestId ? { ...r, ...patch } : r));
    this.writeToStorage(updated);
  }

  private readFromStorage(): DeliveryRequest[] {
    const raw = localStorage.getItem(this.storageKey);
    if (!raw) return [];

    try {
      const parsed = JSON.parse(raw) as DeliveryRequest[];
      return Array.isArray(parsed) ? parsed : [];
    } catch {
      return [];
    }
  }

  private writeToStorage(requests: DeliveryRequest[]): void {
    localStorage.setItem(this.storageKey, JSON.stringify(requests));
  }

  private isFarmerRole(): boolean {
    const role = getDeliveryUserRole();
    return role === 'agriculteur' || role === 'farmer' || role.includes('agric');
  }

  public isUserFarmerRole(): boolean {
    return this.isFarmerRole();
  }

  private toNumericId(id: string): number {
    const direct = Number(id);
    if (Number.isFinite(direct) && direct > 0) return direct;
    const digits = id.replace(/\D/g, '');
    const parsed = Number(digits);
    return Number.isFinite(parsed) && parsed > 0 ? parsed : 0;
  }

  private toBackendTypeByWeight(weightKg: number): 'LOCALE' | 'LONGUE_DISTANCE' {
    return weightKg >= 250 ? 'LONGUE_DISTANCE' : 'LOCALE';
  }

  private normalizeAdminKpis(payload: Record<string, unknown> | null | undefined): DeliveryAdminKpis {
    const source = payload || {};
    return {
      total: this.toNumber(source['total']),
      enAttente: this.toNumber(source['enAttente']),
      acceptees: this.toNumber(source['acceptees']),
      enCours: this.toNumber(source['enCours']),
      livre: this.toNumber(source['livre']),
      annulees: this.toNumber(source['annulees']),
      revenue: this.toNumber(source['revenue']),
      avgPrice: this.toNumber(source['avgPrice']),
      tauxLivraison: this.toNumber(source['tauxLivraison'])
    };
  }

  private emptyAdminKpis(): DeliveryAdminKpis {
    return {
      total: 0,
      enAttente: 0,
      acceptees: 0,
      enCours: 0,
      livre: 0,
      annulees: 0,
      revenue: 0,
      avgPrice: 0,
      tauxLivraison: 0
    };
  }

  private toNumber(value: unknown): number {
    const parsed = Number(value);
    return Number.isFinite(parsed) ? parsed : 0;
  }

  private toBackendStatus(status: DeliveryRequestStatus): string {
    const mapStatus: Record<DeliveryRequestStatus, string> = {
      'En attente': 'EN_ATTENTE',
      'Acceptée': 'ACCEPTEE',
      'En cours': 'EN_COURS',
      'Livrée': 'LIVREE',
      'Refusée': 'ANNULEE'
    };
    return mapStatus[status];
  }

  private fromBackendStatus(status?: string): DeliveryRequestStatus {
    switch ((status || '').toUpperCase()) {
      case 'EN_ATTENTE':
        return 'En attente';
      case 'ACCEPTEE':
        return 'Acceptée';
      case 'EN_COURS':
      case 'RETARD':
        return 'En cours';
      case 'LIVREE':
        return 'Livrée';
      case 'ANNULEE':
      default:
        return 'Refusée';
    }
  }

  private toDateTimePayload(value: string): string {
    if (!value) {
      return value;
    }
    return value.includes('T') ? value : `${value}T00:00:00`;
  }

  private extractBackendErrorMessage(err: any): string {
    const message = err?.error?.message
      || err?.error?.reason
      || err?.error?.error
      || err?.message
      || '';

    if (message && message !== 'Bad Request' && !message.includes('Http failure response')) {
      return message;
    }

    if (err?.status === 400) {
      return 'Operation refusee par le service livraison. Verifiez le planning du jour, la date/heure prevue et les contraintes de prix.';
    }

    if (err?.status === 403) {
      return 'Action non autorisee pour cet utilisateur.';
    }

    if (err?.status === 409) {
      return 'Conflit detecte: cette action n est pas possible dans l etat actuel.';
    }

    return 'Operation impossible pour le moment.';
  }

  private fromApi(api: LivraisonApi): DeliveryRequest {
    const acceptedById = api.transporteurId && api.transporteurId > 0 ? api.transporteurId : undefined;
    const apiAny = api as any;
    const farmerFallbackEmail = apiAny?.createdByEmail || `farmer-${api.agriculteurId}@local`;
    const transporterFallbackEmail = acceptedById
      ? (apiAny?.acceptedByEmail || `transporter-${acceptedById}@local`)
      : undefined;
    const createdByEmail = this.resolveKnownEmail(api.agriculteurId, farmerFallbackEmail);
    const acceptedByEmail = acceptedById
      ? this.resolveKnownEmail(acceptedById, transporterFallbackEmail)
      : undefined;

    this.rememberKnownUser(api.agriculteurId, createdByEmail);
    if (acceptedById && acceptedByEmail) {
      this.rememberKnownUser(acceptedById, acceptedByEmail);
    }

    return {
      id: String(api.id),
      reference: api.reference || `DLV-${api.id}`,
      product: api.typeProduit || 'Produit',
      weightKg: Number(api.poids || 0),
      details: api.detailsDemande || '',
      pickupLabel: api.adresseDepart || `${api.latDepart ?? 0}, ${api.lngDepart ?? 0}`,
      dropoffLabel: api.adresseArrivee || `${api.latArrivee ?? 0}, ${api.lngArrivee ?? 0}`,
      estimatedPrice: Number(api.prix || 0),
      pickupLat: Number(api.latDepart || 0),
      pickupLng: Number(api.lngDepart || 0),
      dropoffLat: Number(api.latArrivee || 0),
      dropoffLng: Number(api.lngArrivee || 0),
      autoGrouping: Boolean(api.estRegroupable),
      status: this.fromBackendStatus(api.status),
      createdByRole: 'Agriculteur',
      createdByEmail,
      createdById: api.agriculteurId,
      acceptedById,
      acceptedByEmail,
      createdAt: api.dateCreation || new Date().toISOString(),
      departureDate: api.dateDepart,
      plannedDeliveryDate: api.dateLivraisonPrevue,
      deliveredAt: api.dateLivraisonEffective,
      grouped: Boolean(api.grouped),
      groupReference: api.groupReference || undefined,
      rating: Number(api.note || 0) || undefined,
      ratingStatus: (api.ratingStatus as DeliveryRequest['ratingStatus']) || undefined,
      currentLat: Number(api.latActuelle || 0) || undefined,
      currentLng: Number(api.lngActuelle || 0) || undefined,
      signatureStatus: api.signatureStatus || undefined
    };
  }

  private upsertFromApi(api: LivraisonApi): void {
    const mapped = this.fromApi(api);
    const all = this.readFromStorage();
    const index = all.findIndex((x) => x.id === mapped.id);
    if (index >= 0) all[index] = mapped;
    else all.unshift(mapped);
    this.writeToStorage(all);
  }

  private removeFromStorage(requestId: string): void {
    const normalizedId = String(this.toNumericId(requestId) || requestId);
    const remaining = this.readFromStorage().filter((item) => item.id !== normalizedId && item.id !== requestId);
    this.writeToStorage(remaining);
  }

  private captureCurrentUserIdentity(): void {
    const id = getDeliveryUserId();
    const emailRaw = getDeliveryUserEmail();
    if (!id || id <= 0 || !emailRaw || emailRaw === 'unknown@local') {
      return;
    }
    this.rememberKnownUser(id, emailRaw);
  }

  private readKnownUsers(): Record<string, string> {
    try {
      const raw = localStorage.getItem(this.usersDirectoryKey);
      const parsed = raw ? JSON.parse(raw) : {};
      return parsed && typeof parsed === 'object' ? parsed : {};
    } catch {
      return {};
    }
  }

  private writeKnownUsers(users: Record<string, string>): void {
    localStorage.setItem(this.usersDirectoryKey, JSON.stringify(users));
  }

  private rememberKnownUser(userId: number, email?: string): void {
    if (!Number.isFinite(userId) || userId <= 0 || !email) {
      return;
    }
    const normalizedEmail = String(email).trim().toLowerCase();
    if (!normalizedEmail) {
      return;
    }
    const users = this.readKnownUsers();
    users[String(userId)] = normalizedEmail;
    this.writeKnownUsers(users);
  }

  private resolveKnownEmail(userId: number, fallbackEmail?: string): string {
    const users = this.readKnownUsers();
    const known = users[String(userId)];
    if (known) {
      return known;
    }
    return fallbackEmail || 'unknown@local';
  }
}

import { Injectable } from '@angular/core';
import { HttpClient, HttpParams } from '@angular/common/http';
import { Observable, catchError, map, of, switchMap, tap } from 'rxjs';
import { getDeliveryUserEmail, getDeliveryUserId, getDeliveryUserRole } from './delivery-auth.helper';

export type DeliveryRequestStatus = 'En attente' | 'Acceptée' | 'En cours' | 'Livrée' | 'Refusée';

export type DeliveryRequest = {
  id: string;
  reference: string;
  product: string;
  weightKg: number;
  details: string;
  pickupLabel: string;
  dropoffLabel: string;
  estimatedPrice: number;
  pickupLat: number;
  pickupLng: number;
  dropoffLat: number;
  dropoffLng: number;
  autoGrouping: boolean;
  status: DeliveryRequestStatus;
  createdByRole: 'Agriculteur' | 'Transporteur';
  createdByEmail: string;
  createdById?: number;
  acceptedByEmail?: string;
  acceptedById?: number;
  createdAt: string;
  departureDate?: string;
  plannedDeliveryDate?: string;
  deliveredAt?: string;
  grouped?: boolean;
  groupReference?: string;
  rating?: number;
  ratingStatus?: 'PENDING' | 'RATED' | 'IGNORED';
  currentLat?: number;
  currentLng?: number;
};

export type DeliveryRequestInput = {
  reference: string;
  product: string;
  weightKg: number;
  details: string;
  departureDate?: string;
  pickupLabel: string;
  dropoffLabel: string;
  estimatedPrice: number;
  pickupLat: number;
  pickupLng: number;
  dropoffLat: number;
  dropoffLng: number;
  autoGrouping: boolean;
};

export type FarmerKnownTransporter = {
  transporteurId: number;
  displayName: string;
  completedDeliveries: number;
  lastDeliveryAt?: string;
};

export type TargetedCreateResult = {
  delivery: DeliveryRequest | null;
  errorMessage?: string;
};

export type DeliveryPriceEstimate = {
  estimatedPrice: number;
  distanceKm: number;
  durationHours: number;
  weatherSurchargePercent: number;
  weatherCondition: string;
};

export type LivraisonApi = {
  id: number;
  reference: string;
  type?: string;
  status?: string;
  statusDemande?: string;
  agriculteurId: number;
  transporteurId: number;
  dateCreation?: string;
  dateDepart?: string;
  datePreferenceAgriculteur?: string;
  dateProposeeNegociation?: string;
  dateLivraisonPrevue?: string;
  dateLivraisonEffective?: string;
  adresseDepart?: string;
  adresseArrivee?: string;
  latDepart?: number;
  lngDepart?: number;
  latArrivee?: number;
  lngArrivee?: number;
  latActuelle?: number;
  lngActuelle?: number;
  poids?: number;
  volume?: number;
  typeProduit?: string;
  detailsDemande?: string;
  estRegroupable?: boolean;
  prix?: number;
  note?: number;
  ratingStatus?: string;
  grouped?: boolean;
  groupReference?: string;
};

export type AcceptTransporterResult = {
  success: boolean;
  delivery?: LivraisonApi | null;
  errorMessage?: string;
};

export type DeliveryAdminKpis = {
  total: number;
  enAttente: number;
  acceptees: number;
  enCours: number;
  livre: number;
  annulees: number;
  revenue: number;
  avgPrice: number;
  tauxLivraison: number;
};

@Injectable()
export class DeliveryRequestService {
  private readonly storageKey = 'deliveryRequests';
  private readonly usersDirectoryKey = 'deliveryKnownUsers';
  private readonly apiBase = '/livraison/api/livraisons';

  constructor(private http: HttpClient) {
    this.captureCurrentUserIdentity();
  }

  getCurrentUserEmail(): string {
    return getDeliveryUserEmail();
  }

  getCurrentUserId(): number {
    return getDeliveryUserId() ?? 0;
  }

  getAdminKpis(): Observable<DeliveryAdminKpis> {
    return this.http.get<Record<string, unknown>>(`${this.apiBase}/admin/kpis`).pipe(
      map((payload) => this.normalizeAdminKpis(payload)),
      catchError((err) => {
        console.warn('Load admin KPIs failed, using computed fallback.', err);
        return of(this.emptyAdminKpis());
      })
    );
  }

  refreshFromBackend(): Observable<DeliveryRequest[]> {
    let params = new HttpParams();
    if (this.isFarmerRole()) {
      params = params.set('agriculteurId', String(this.getCurrentUserId()));
    }

    return this.http.get<LivraisonApi[]>(this.apiBase, { params }).pipe(
      map((items) => items.map((x) => this.fromApi(x))),
      tap((mapped) => this.writeToStorage(mapped)),
      catchError((err) => {
        console.warn('Delivery refresh failed, clearing local cache to avoid stale UI.', err);
        this.writeToStorage([]);
        return of([]);
      })
    );
  }

  getApiById(requestId: string): Observable<LivraisonApi | null> {
    const numericId = this.toNumericId(requestId);
    if (!numericId) {
      return of(null);
    }

    return this.http.get<LivraisonApi>(`${this.apiBase}/${numericId}`).pipe(
      tap((api) => this.upsertFromApi(api)),
      catchError((err) => {
        console.warn('Load livraison by id failed.', err);
        return of(null);
      })
    );
  }

  createApiDelivery(payload: Partial<LivraisonApi>): Observable<LivraisonApi | null> {
    return this.http.post<LivraisonApi>(this.apiBase, payload).pipe(
      tap((saved) => this.upsertFromApi(saved)),
      catchError((err) => {
        console.warn('Create livraison failed.', err);
        return of(null);
      })
    );
  }

  updateApiDelivery(requestId: string, payload: Partial<LivraisonApi>): Observable<LivraisonApi | null> {
    const numericId = this.toNumericId(requestId);
    if (!numericId) {
      return of(null);
    }

    return this.http.put<LivraisonApi>(`${this.apiBase}/${numericId}`, payload).pipe(
      tap((updated) => this.upsertFromApi(updated)),
      catchError((err) => {
        console.warn('Update livraison failed.', err);
        return of(null);
      })
    );
  }

  deleteApiDelivery(requestId: string): Observable<boolean> {
    const numericId = this.toNumericId(requestId);
    if (!numericId) {
      return of(false);
    }

    return this.http.delete<void>(`${this.apiBase}/${numericId}`).pipe(
      tap(() => this.removeFromStorage(String(numericId))),
      map(() => true),
      catchError((err) => {
        console.warn('Delete livraison failed.', err);
        return of(false);
      })
    );
  }

  assignTransporteur(requestId: string, transporteurId: number): Observable<LivraisonApi | null> {
    const numericId = this.toNumericId(requestId);
    if (!numericId || !transporteurId) {
      return of(null);
    }

    return this.http.put<LivraisonApi>(`${this.apiBase}/${numericId}/assign`, null, {
      params: new HttpParams().set('transporteurId', String(transporteurId))
    }).pipe(
      tap((updated) => this.upsertFromApi(updated)),
      catchError((err) => {
        console.warn('Assign transporteur failed.', err);
        return of(null);
      })
    );
  }

  updateCurrentPosition(requestId: string, lat: number, lng: number): Observable<LivraisonApi | null> {
    const numericId = this.toNumericId(requestId);
    if (!numericId || !Number.isFinite(lat) || !Number.isFinite(lng)) {
      return of(null);
    }

    return this.http.put<LivraisonApi>(`${this.apiBase}/${numericId}/gps`, null, {
      params: new HttpParams()
        .set('lat', String(lat))
        .set('lng', String(lng))
    }).pipe(
      tap((updated) => this.upsertFromApi(updated)),
      catchError((err) => {
        console.warn('Update GPS failed.', err);
        return of(null);
      })
    );
  }

  evaluerTransporteur(requestId: string, note: number, evaluateurId?: number): Observable<LivraisonApi | null> {
    const numericId = this.toNumericId(requestId);
    if (!numericId || !Number.isFinite(note)) {
      return of(null);
    }

    let params = new HttpParams().set('note', String(note));
    if (evaluateurId) {
      params = params.set('evaluateurId', String(evaluateurId));
    }

    return this.http.put<LivraisonApi>(`${this.apiBase}/${numericId}/note`, null, { params }).pipe(
      tap((updated) => this.upsertFromApi(updated)),
      catchError((err) => {
        console.warn('Evaluation transporteur failed.', err);
        return of(null);
      })
    );
  }

  ignorerNotationTransporteur(requestId: string, agriculteurId?: number): Observable<LivraisonApi | null> {
    const numericId = this.toNumericId(requestId);
    const ownerId = agriculteurId || this.getCurrentUserId();
    if (!numericId || !ownerId) {
      return of(null);
    }

    return this.http.post<LivraisonApi>(`${this.apiBase}/${numericId}/rating/ignore`, null, {
      params: new HttpParams().set('agriculteurId', String(ownerId))
    }).pipe(
      tap((updated) => this.upsertFromApi(updated)),
      catchError((err) => {
        console.warn('Ignore rating failed.', err);
        return of(null);
      })
    );
  }

  getAll(): DeliveryRequest[] {
    const parsed = this.readFromStorage();
    return parsed.sort((a, b) => (a.createdAt < b.createdAt ? 1 : -1));
  }

  getPendingFarmerRequests(): DeliveryRequest[] {
    return this.getAll().filter(
      (r) => r.createdByRole === 'Agriculteur' && r.status === 'En attente'
    );
  }

  getForCurrentFarmer(): DeliveryRequest[] {
    const userId = this.getCurrentUserId();
    return this.getAll().filter(
      (r) => r.createdByRole === 'Agriculteur' && r.createdById === userId
    );
  }

  getInProgressForCurrentFarmer(): DeliveryRequest[] {
    return this.getForCurrentFarmer().filter((r) => r.status === 'En cours');
  }

  getById(requestId: string): DeliveryRequest | null {
    return this.getAll().find((r) => r.id === requestId) || null;
  }

  getTransporterActiveRequests(): DeliveryRequest[] {
    const userId = this.getCurrentUserId();
    return this.getAll().filter(
      (r) => r.acceptedById === userId && (r.status === 'Acceptée' || r.status === 'En cours')
    );
  }

  getTransporterInProgressRequests(): DeliveryRequest[] {
    const userId = this.getCurrentUserId();
    return this.getAll().filter((r) => r.acceptedById === userId && r.status === 'En cours');
  }

  getTransporterHistoryRequests(): DeliveryRequest[] {
    const userId = this.getCurrentUserId();
    return this.getAll().filter((r) => r.acceptedById === userId && r.status === 'Livrée');
  }

  getTransporterTimelineRequests(): DeliveryRequest[] {
    const userId = this.getCurrentUserId();
    return this.getAll().filter(
      (r) => r.acceptedById === userId && (r.status === 'Acceptée' || r.status === 'En cours' || r.status === 'Livrée')
    );
  }

  getFarmerTimelineRequests(): DeliveryRequest[] {
    return this.getForCurrentFarmer().filter(
      (r) => r.status === 'Acceptée' || r.status === 'En cours' || r.status === 'Livrée'
    );
  }

  getTransporterCalendarRequests(): DeliveryRequest[] {
    const userId = this.getCurrentUserId();
    return this.getAll().filter(
      (r) => r.acceptedById === userId && (r.status === 'Acceptée' || r.status === 'En cours' || r.status === 'Livrée')
    );
  }

  acceptByCurrentTransporter(requestId: string): Observable<AcceptTransporterResult> {
    const numericId = this.toNumericId(requestId);
    const transporterId = this.getCurrentUserId();
    const previous = this.getById(requestId);

    if (!numericId) {
      return of({
        success: false,
        errorMessage: 'Identifiant de livraison invalide.'
      });
    }

    // Optimistic UI update
    this.updateRequest(requestId, {
      status: 'Acceptée',
      acceptedById: transporterId,
      acceptedByEmail: this.getCurrentUserEmail()
    });

    return this.http.put<LivraisonApi>(`${this.apiBase}/${numericId}/assign`, null, {
      params: new HttpParams().set('transporteurId', String(transporterId))
    }).pipe(
      tap((updated) => this.upsertFromApi(updated)),
      switchMap((assigned) => this.http.put<LivraisonApi>(`${this.apiBase}/${numericId}/status`, null, {
        params: new HttpParams().set('status', 'ACCEPTEE')
      }).pipe(
        tap((updated) => this.upsertFromApi(updated)),
        catchError((err) => {
          console.warn('Accept transporter status sync failed after assign.', err);
          return of(assigned);
        })
      )),
      map((updated) => ({
        success: true,
        delivery: updated
      })),
      catchError((err) => {
        console.warn('Accept transporter backend sync failed.', err);
        if (previous) {
          this.updateRequest(requestId, {
            status: previous.status,
            acceptedById: previous.acceptedById,
            acceptedByEmail: previous.acceptedByEmail
          });
        }
        return of({
          success: false,
          errorMessage: this.extractBackendErrorMessage(err)
        });
      })
    );
  }

  startRouteToPickup(requestId: string): Observable<AcceptTransporterResult> {
    const numericId = this.toNumericId(requestId);
    const transporterId = this.getCurrentUserId();
    if (!numericId || !transporterId) {
      return of({ success: false, errorMessage: 'Identifiant de livraison invalide.' });
    }

    const blockingRequest = this.getTransporterInProgressRequests().find((r) => r.id !== requestId);
    if (blockingRequest) {
      return of({
        success: false,
        errorMessage: `Vous avez deja une livraison en cours (${blockingRequest.reference}). Terminez-la ou annulez-la avant d'en commencer une autre.`
      });
    }

    return this.http.post<LivraisonApi>(`${this.apiBase}/${numericId}/start-route`, null, {
      params: new HttpParams().set('transporteurId', String(transporterId))
    }).pipe(
      tap((updated) => this.upsertFromApi(updated)),
      map((updated) => ({ success: true, delivery: updated })),
      catchError((err) => {
        console.warn('Start route backend sync failed.', err);
        return of({ success: false, errorMessage: this.extractBackendErrorMessage(err) });
      })
    );
  }

  createFromFarmer(input: DeliveryRequestInput): Observable<DeliveryRequest | null> {
    const currentUserId = this.getCurrentUserId();
    const payload = {
      reference: input.reference,
      type: this.toBackendTypeByWeight(input.weightKg),
      status: 'EN_ATTENTE',
      agriculteurId: currentUserId,
      transporteurId: 0,
      dateDepart: input.departureDate ? this.toDateTimePayload(input.departureDate) : undefined,
      datePreferenceAgriculteur: input.departureDate ? this.toDateTimePayload(input.departureDate) : undefined,
      adresseDepart: input.pickupLabel,
      adresseArrivee: input.dropoffLabel,
      latDepart: input.pickupLat,
      lngDepart: input.pickupLng,
      latArrivee: input.dropoffLat,
      lngArrivee: input.dropoffLng,
      poids: input.weightKg,
      typeProduit: input.product,
      detailsDemande: input.details,
      estRegroupable: input.autoGrouping,
      prix: input.estimatedPrice
    };

    return this.createApiDelivery(payload).pipe(
      map((saved) => (saved ? this.fromApi(saved) : null))
    );
  }

  getPreferredTransportersForCurrentFarmer(): Observable<FarmerKnownTransporter[]> {
    const agriculteurId = this.getCurrentUserId();
    if (!agriculteurId) {
      return of([]);
    }

    return this.http.get<FarmerKnownTransporter[]>(`${this.apiBase}/agriculteur/${agriculteurId}/transporteurs-preferes`).pipe(
      map((items) => Array.isArray(items) ? items : []),
      catchError((err) => {
        console.warn('Load preferred transporters failed.', err);
        return of([]);
      })
    );
  }

  createFromFarmerToTransporter(input: DeliveryRequestInput, transporteurId: number): Observable<TargetedCreateResult> {
    const agriculteurId = this.getCurrentUserId();
    if (!agriculteurId || !transporteurId) {
      return of({
        delivery: null,
        errorMessage: 'Transporteur invalide.'
      });
    }

    const payload = {
      reference: input.reference,
      product: input.product,
      weightKg: input.weightKg,
      details: input.details,
      departureDate: input.departureDate ? this.toDateTimePayload(input.departureDate) : undefined,
      pickupLabel: input.pickupLabel,
      dropoffLabel: input.dropoffLabel,
      estimatedPrice: input.estimatedPrice,
      pickupLat: input.pickupLat,
      pickupLng: input.pickupLng,
      dropoffLat: input.dropoffLat,
      dropoffLng: input.dropoffLng,
      autoGrouping: input.autoGrouping,
      transporteurId
    };

    return this.http.post<LivraisonApi>(`${this.apiBase}/agriculteur/${agriculteurId}/livraisons/cibler-transporteur`, payload).pipe(
      tap((saved) => this.upsertFromApi(saved)),
      map((saved) => ({
        delivery: saved ? this.fromApi(saved) : null
      })),
      catchError((err) => {
        console.warn('Create targeted delivery failed.', err);
        return of({
          delivery: null,
          errorMessage: this.extractBackendErrorMessage(err)
        });
      })
    );
  }

  estimateDeliveryPrice(input: {
    pickupLat: number;
    pickupLng: number;
    dropoffLat: number;
    dropoffLng: number;
    weightKg: number;
    autoGrouping: boolean;
    distanceKm?: number;
    durationHours?: number;
  }): Observable<DeliveryPriceEstimate | null> {
    const payload = {
      pickupLat: input.pickupLat,
      pickupLng: input.pickupLng,
      dropoffLat: input.dropoffLat,
      dropoffLng: input.dropoffLng,
      weightKg: input.weightKg,
      autoGrouping: input.autoGrouping,
      distanceKm: input.distanceKm,
      durationHours: input.durationHours
    };

    return this.http.post<DeliveryPriceEstimate>(`${this.apiBase}/pricing/estimate`, payload).pipe(
      map((estimate) => estimate || null),
      catchError((err) => {
        console.warn('Estimate delivery price failed.', err);
        return of(null);
      })
    );
  }

  updateStatus(requestId: string, status: DeliveryRequestStatus): void {
    this.updateStatusApi(requestId, status).subscribe();
  }

  updateStatusApi(requestId: string, status: DeliveryRequestStatus): Observable<LivraisonApi | null> {
    this.updateRequest(requestId, { status });

    const numericId = this.toNumericId(requestId);
    if (!numericId) {
      return of(null);
    }

    return this.http.put<LivraisonApi>(`${this.apiBase}/${numericId}/status`, null, {
      params: new HttpParams().set('status', this.toBackendStatus(status))
    }).pipe(
      tap((updated) => this.upsertFromApi(updated)),
      catchError((err) => {
        console.warn('Update status backend sync failed.', err);
        return of(null);
      })
    );
  }

  updateRequest(requestId: string, patch: Partial<DeliveryRequest>): void {
    const requests = this.readFromStorage();
    const updated = requests.map((r) => (r.id === requestId ? { ...r, ...patch } : r));
    this.writeToStorage(updated);
  }

  private readFromStorage(): DeliveryRequest[] {
    const raw = localStorage.getItem(this.storageKey);
    if (!raw) return [];

    try {
      const parsed = JSON.parse(raw) as DeliveryRequest[];
      return Array.isArray(parsed) ? parsed : [];
    } catch {
      return [];
    }
  }

  private writeToStorage(requests: DeliveryRequest[]): void {
    localStorage.setItem(this.storageKey, JSON.stringify(requests));
  }

  private isFarmerRole(): boolean {
    const role = getDeliveryUserRole();
    return role === 'agriculteur' || role === 'farmer' || role.includes('agric');
  }

  public isUserFarmerRole(): boolean {
    return this.isFarmerRole();
  }

  private toNumericId(id: string): number {
    const direct = Number(id);
    if (Number.isFinite(direct) && direct > 0) return direct;
    const digits = id.replace(/\D/g, '');
    const parsed = Number(digits);
    return Number.isFinite(parsed) && parsed > 0 ? parsed : 0;
  }

  private toBackendTypeByWeight(weightKg: number): 'LOCALE' | 'LONGUE_DISTANCE' {
    return weightKg >= 250 ? 'LONGUE_DISTANCE' : 'LOCALE';
  }

  private normalizeAdminKpis(payload: Record<string, unknown> | null | undefined): DeliveryAdminKpis {
    const source = payload || {};
    return {
      total: this.toNumber(source['total']),
      enAttente: this.toNumber(source['enAttente']),
      acceptees: this.toNumber(source['acceptees']),
      enCours: this.toNumber(source['enCours']),
      livre: this.toNumber(source['livre']),
      annulees: this.toNumber(source['annulees']),
      revenue: this.toNumber(source['revenue']),
      avgPrice: this.toNumber(source['avgPrice']),
      tauxLivraison: this.toNumber(source['tauxLivraison'])
    };
  }

  private emptyAdminKpis(): DeliveryAdminKpis {
    return {
      total: 0,
      enAttente: 0,
      acceptees: 0,
      enCours: 0,
      livre: 0,
      annulees: 0,
      revenue: 0,
      avgPrice: 0,
      tauxLivraison: 0
    };
  }

  private toNumber(value: unknown): number {
    const parsed = Number(value);
    return Number.isFinite(parsed) ? parsed : 0;
  }

  private toBackendStatus(status: DeliveryRequestStatus): string {
    const mapStatus: Record<DeliveryRequestStatus, string> = {
      'En attente': 'EN_ATTENTE',
      'Acceptée': 'ACCEPTEE',
      'En cours': 'EN_COURS',
      'Livrée': 'LIVREE',
      'Refusée': 'ANNULEE'
    };
    return mapStatus[status];
  }

  private fromBackendStatus(status?: string): DeliveryRequestStatus {
    switch ((status || '').toUpperCase()) {
      case 'EN_ATTENTE':
        return 'En attente';
      case 'ACCEPTEE':
        return 'Acceptée';
      case 'EN_COURS':
      case 'RETARD':
        return 'En cours';
      case 'LIVREE':
        return 'Livrée';
      case 'ANNULEE':
      default:
        return 'Refusée';
    }
  }

  private toDateTimePayload(value: string): string {
    if (!value) {
      return value;
    }
    return value.includes('T') ? value : `${value}T00:00:00`;
  }

  private extractBackendErrorMessage(err: any): string {
    const message = err?.error?.message
      || err?.error?.reason
      || err?.error?.error
      || err?.message
      || '';

    if (message && message !== 'Bad Request' && !message.includes('Http failure response')) {
      return message;
    }

    if (err?.status === 400) {
      return 'Operation refusee par le service livraison. Verifiez le planning du jour, la date/heure prevue et les contraintes de prix.';
    }

    if (err?.status === 403) {
      return 'Action non autorisee pour cet utilisateur.';
    }

    if (err?.status === 409) {
      return 'Conflit detecte: cette action n est pas possible dans l etat actuel.';
    }

    return 'Operation impossible pour le moment.';
  }

  private fromApi(api: LivraisonApi): DeliveryRequest {
    const acceptedById = api.transporteurId && api.transporteurId > 0 ? api.transporteurId : undefined;
    const apiAny = api as any;
    const farmerFallbackEmail = apiAny?.createdByEmail || `farmer-${api.agriculteurId}@local`;
    const transporterFallbackEmail = acceptedById
      ? (apiAny?.acceptedByEmail || `transporter-${acceptedById}@local`)
      : undefined;
    const createdByEmail = this.resolveKnownEmail(api.agriculteurId, farmerFallbackEmail);
    const acceptedByEmail = acceptedById
      ? this.resolveKnownEmail(acceptedById, transporterFallbackEmail)
      : undefined;

    this.rememberKnownUser(api.agriculteurId, createdByEmail);
    if (acceptedById && acceptedByEmail) {
      this.rememberKnownUser(acceptedById, acceptedByEmail);
    }

    return {
      id: String(api.id),
      reference: api.reference || `DLV-${api.id}`,
      product: api.typeProduit || 'Produit',
      weightKg: Number(api.poids || 0),
      details: api.detailsDemande || '',
      pickupLabel: api.adresseDepart || `${api.latDepart ?? 0}, ${api.lngDepart ?? 0}`,
      dropoffLabel: api.adresseArrivee || `${api.latArrivee ?? 0}, ${api.lngArrivee ?? 0}`,
      estimatedPrice: Number(api.prix || 0),
      pickupLat: Number(api.latDepart || 0),
      pickupLng: Number(api.lngDepart || 0),
      dropoffLat: Number(api.latArrivee || 0),
      dropoffLng: Number(api.lngArrivee || 0),
      autoGrouping: Boolean(api.estRegroupable),
      status: this.fromBackendStatus(api.status),
      createdByRole: 'Agriculteur',
      createdByEmail,
      createdById: api.agriculteurId,
      acceptedById,
      acceptedByEmail,
      createdAt: api.dateCreation || new Date().toISOString(),
      departureDate: api.dateDepart,
      plannedDeliveryDate: api.dateLivraisonPrevue,
      deliveredAt: api.dateLivraisonEffective,
      grouped: Boolean(api.grouped),
      groupReference: api.groupReference || undefined,
      rating: Number(api.note || 0) || undefined,
      ratingStatus: (api.ratingStatus as DeliveryRequest['ratingStatus']) || undefined,
      currentLat: Number(api.latActuelle || 0) || undefined,
      currentLng: Number(api.lngActuelle || 0) || undefined
    };
  }

  private upsertFromApi(api: LivraisonApi): void {
    const mapped = this.fromApi(api);
    const all = this.readFromStorage();
    const index = all.findIndex((x) => x.id === mapped.id);
    if (index >= 0) all[index] = mapped;
    else all.unshift(mapped);
    this.writeToStorage(all);
  }

  private removeFromStorage(requestId: string): void {
    const normalizedId = String(this.toNumericId(requestId) || requestId);
    const remaining = this.readFromStorage().filter((item) => item.id !== normalizedId && item.id !== requestId);
    this.writeToStorage(remaining);
  }

  private captureCurrentUserIdentity(): void {
    const id = getDeliveryUserId();
    const emailRaw = getDeliveryUserEmail();
    if (!id || id <= 0 || !emailRaw || emailRaw === 'unknown@local') {
      return;
    }
    this.rememberKnownUser(id, emailRaw);
  }

  private readKnownUsers(): Record<string, string> {
    try {
      const raw = localStorage.getItem(this.usersDirectoryKey);
      const parsed = raw ? JSON.parse(raw) : {};
      return parsed && typeof parsed === 'object' ? parsed : {};
    } catch {
      return {};
    }
  }

  private writeKnownUsers(users: Record<string, string>): void {
    localStorage.setItem(this.usersDirectoryKey, JSON.stringify(users));
  }

  private rememberKnownUser(userId: number, email?: string): void {
    if (!Number.isFinite(userId) || userId <= 0 || !email) {
      return;
    }
    const normalizedEmail = String(email).trim().toLowerCase();
    if (!normalizedEmail) {
      return;
    }
    const users = this.readKnownUsers();
    users[String(userId)] = normalizedEmail;
    this.writeKnownUsers(users);
  }

  private resolveKnownEmail(userId: number, fallbackEmail?: string): string {
    const users = this.readKnownUsers();
    const known = users[String(userId)];
    if (known) {
      return known;
    }
    return fallbackEmail || 'unknown@local';
  }
}

import { Injectable } from '@angular/core';
import {
  HttpEvent,
  HttpHandler,
  HttpInterceptor,
  HttpRequest
} from '@angular/common/http';
import { Observable } from 'rxjs';

@Injectable()
export class AuthTokenInterceptor implements HttpInterceptor {
  intercept(req: HttpRequest<unknown>, next: HttpHandler): Observable<HttpEvent<unknown>> {
    const token = localStorage.getItem('authToken');
    if (!token) {
      return next.handle(req);
    }

    const isApiRequest = req.url.startsWith('http://localhost:8089/')
      || req.url.startsWith('/forums/')
      || req.url.startsWith('/user/');

    if (!isApiRequest) {
      return next.handle(req);
    }

    const authReq = req.clone({
      setHeaders: {
        Authorization: `Bearer ${token}`
      }
    });

    return next.handle(authReq);
  }
}

