@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;500;600;700;800&family=Poppins:wght@300;400;500;600;700&display=swap');

/* ---- CSS Variables ---- */
:root {
  --primary: #4caf50;
  --primary-dark: #388e3c;
  --primary-light: #81c784;
  --secondary: #ff8f00;
  --secondary-dark: #e65100;
  --accent: #f9a825;
  --dark: #1a1a2e;
  --dark-2: #2d2d44;
  --text: #555;
  --text-light: #888;
  --light-bg: #f5f8f0;
  --white: #fff;
  --border: #e0e0e0;
  --shadow: 0 10px 40px rgba(0,0,0,0.1);
  --shadow-green: 0 10px 40px rgba(76,175,80,0.25);
  --radius: 12px;
  --transition: all 0.4s cubic-bezier(0.25, 0.8, 0.25, 1);
}

/* ---- Reset ---- */
*, *::before, *::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
  overflow-x: hidden;
}

body {
  font-family: 'Poppins', sans-serif;
  color: var(--text);
  background: var(--white);
  overflow-x: hidden;
}

h1, h2, h3, h4, h5, h6 {
  font-family: 'Playfair Display', serif;
  color: var(--dark);
  line-height: 1.2;
}

a {
  text-decoration: none;
  color: inherit;
  transition: var(--transition);
}

ul { list-style: none; }

img {
  max-width: 100%;
  display: block;
}

/* ---- Utility ---- */
.container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
}

.section-padding {
  padding: 100px 0;
}

.section-header {
  text-align: center;
  margin-bottom: 60px;
}

.section-label {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  font-size: 14px;
  font-weight: 600;
  color: var(--primary);
  text-transform: uppercase;
  letter-spacing: 3px;
  margin-bottom: 15px;
}

.section-label::before,
.section-label::after {
  content: '';
  width: 30px;
  height: 2px;
  background: var(--primary);
}

.section-title {
  font-size: clamp(30px, 4vw, 48px);
  font-weight: 700;
  color: var(--dark);
  margin-bottom: 20px;
  line-height: 1.2;
}

.section-title span {
  color: var(--primary);
}

.section-desc {
  font-size: 16px;
  color: var(--text-light);
  max-width: 600px;
  margin: 0 auto;
  line-height: 1.8;
}

/* ---- Buttons ---- */
.btn {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 14px 32px;
  border-radius: 50px;
  font-family: 'Poppins', sans-serif;
  font-size: 15px;
  font-weight: 600;
  cursor: pointer;
  border: 2px solid transparent;
  transition: var(--transition);
  text-transform: capitalize;
}

.btn-primary {
  background: var(--primary);
  color: var(--white);
  border-color: var(--primary);
}

.btn-primary:hover {
  background: var(--primary-dark);
  border-color: var(--primary-dark);
  transform: translateY(-3px);
  box-shadow: var(--shadow-green);
}

.btn-outline {
  background: transparent;
  color: var(--white);
  border-color: var(--white);
}

.btn-outline:hover {
  background: var(--white);
  color: var(--primary);
  transform: translateY(-3px);
}

.btn-secondary {
  background: var(--secondary);
  color: var(--white);
  border-color: var(--secondary);
}

.btn-secondary:hover {
  background: var(--secondary-dark);
  transform: translateY(-3px);
  box-shadow: 0 10px 30px rgba(255,143,0,0.3);
}
/* Animation pour texte : gauche -> droite avec blur */
.text-animate {
  display: inline-block;
  opacity: 0;
  filter: blur(10px);
  transform: translateX(-50px);
  animation: slideInBlur 1s forwards;
}

@keyframes slideInBlur {
  0% {
    opacity: 0;
    transform: translateX(-50px);
    filter: blur(10px);
  }
  100% {
    opacity: 1;
    transform: translateX(0);
    filter: blur(0);
  }
}

/* Applique uniquement aux slides actifs */
.slide-text .text-animate {
  opacity: 0;
}

.slide-text.active .text-animate {
  animation: slideInBlur 1s forwards;
}

/* ---- Scroll Animations ---- */
.reveal {
  opacity: 0;
  transform: translateY(50px);
  transition: opacity 0.7s ease, transform 0.7s ease;
}

.reveal.visible {
  opacity: 1;
  transform: translateY(0);
}

.reveal-left {
  opacity: 0;
  transform: translateX(-60px);
  transition: opacity 0.7s ease, transform 0.7s ease;
}

.reveal-left.visible {
  opacity: 1;
  transform: translateX(0);
}

.reveal-right {
  opacity: 0;
  transform: translateX(60px);
  transition: opacity 0.7s ease, transform 0.7s ease;
}

.reveal-right.visible {
  opacity: 1;
  transform: translateX(0);
}

/* ---- Animations ---- */
@keyframes fadeInUp {
  from { opacity: 0; transform: translateY(40px); }
  to   { opacity: 1; transform: translateY(0); }
}

@keyframes fadeInLeft {
  from { opacity: 0; transform: translateX(-40px); }
  to   { opacity: 1; transform: translateX(0); }
}

@keyframes fadeInRight {
  from { opacity: 0; transform: translateX(40px); }
  to   { opacity: 1; transform: translateX(0); }
}

@keyframes float {
  0%, 100% { transform: translateY(0); }
  50%       { transform: translateY(-15px); }
}

@keyframes pulse-green {
  0%, 100% { box-shadow: 0 0 0 0 rgba(76,175,80,0.4); }
  50%       { box-shadow: 0 0 0 20px rgba(76,175,80,0); }
}

@keyframes rotate {
  from { transform: rotate(0deg); }
  to   { transform: rotate(360deg); }
}

@keyframes shimmer {
  0%   { background-position: -200% 0; }
  100% { background-position: 200% 0; }
}

@keyframes countUp {
  from { opacity: 0; transform: scale(0.5); }
  to   { opacity: 1; transform: scale(1); }
}

@keyframes leafSway {
  0%, 100% { transform: rotate(-5deg); }
  50%       { transform: rotate(5deg); }
}

/* ---- Badge ---- */
.badge {
  display: inline-block;
  background: var(--primary);
  color: white;
  font-size: 12px;
  font-weight: 600;
  padding: 4px 12px;
  border-radius: 20px;
  text-transform: uppercase;
  letter-spacing: 1px;
}

/* ---- Preloader ---- */
.preloader {
  position: fixed;
  inset: 0;
  background: var(--white);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 9999;
  transition: opacity 0.5s ease, visibility 0.5s ease;
}

.preloader.hidden {
  opacity: 0;
  visibility: hidden;
}

.preloader-inner {
  text-align: center;
}

.preloader-logo {
  font-family: 'Playfair Display', serif;
  font-size: 36px;
  font-weight: 700;
  color: var(--primary);
  margin-bottom: 20px;
}

.preloader-bar {
  width: 200px;
  height: 3px;
  background: #eee;
  border-radius: 3px;
  overflow: hidden;
  margin: 0 auto;
}

.preloader-fill {
  height: 100%;
  background: linear-gradient(90deg, var(--primary), var(--secondary));
  border-radius: 3px;
  animation: preloadFill 1.5s ease forwards;
}

@keyframes preloadFill {
  from { width: 0; }
  to   { width: 100%; }
}

/* ---- Responsive ---- */
@media (max-width: 992px) {
  .section-padding { padding: 70px 0; }
}

@media (max-width: 768px) {
  .section-padding { padding: 60px 0; }
  .section-header { margin-bottom: 40px; }
}

@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;500;600;700;800&family=Poppins:wght@300;400;500;600;700&display=swap');
